def fallback_script(topic: str) -> str:
    clean_topic = topic.strip() or "这个主题"
    return (
        f"你有没有想过，{clean_topic}？这背后不是单一现象，而是一组正在变化的使用场景。"
        f"先看它在日常里怎么发生，再拆开关键原因，最后给出一个判断框架：当我们讨论{clean_topic}，"
        "真正要看的不是表面的形式，而是它承接了哪一类新的需求。"
    )


class VideoStudioGenerationError(RuntimeError):
    def __init__(self, message: str, *, diagnostics: Dict[str, Any] | None = None):
        super().__init__(message)
        self.diagnostics = diagnostics or {}


def generate_storyboard_from_creative_plan(
    creative_plan: Dict[str, Any],
    production_format: str,
    director_document: Dict[str, Any] | None,
) -> List[Dict[str, Any]]:
    scenes = creative_plan.get("scenes") if isinstance(creative_plan.get("scenes"), list) else []
    groups = []
    for scene_index, scene in enumerate(scenes, start=1):
        if not isinstance(scene, dict):
            continue
        units = scene.get("voiceover_units") if isinstance(scene.get("voiceover_units"), list) else []
        if not units:
            continue
        asset_plan = scene.get("asset_search_plan") if isinstance(scene.get("asset_search_plan"), dict) else {}
        mg_director = scene.get("mg_director") if isinstance(scene.get("mg_director"), dict) else {}
        mg_unit_ids = {
            str(item)
            for item in mg_director.get("bound_voiceover_unit_ids", [])
            if str(item).strip()
        }
        if not mg_unit_ids and _mg_director_enabled(mg_director):
            mg_unit_ids = {str(unit.get("id") or "") for unit in units if isinstance(unit, dict) and str(unit.get("id") or "").strip()}
        shots = []
        mg_shot_indexes: List[int] = []
        for unit_index, unit in enumerate(units, start=1):
            if not isinstance(unit, dict):
                continue
            narration = str(unit.get("text") or "").strip()
            if not narration:
                continue
            duration = _positive_int(unit.get("duration_seconds"), _positive_int(asset_plan.get("duration_seconds"), 7))
            unit_id = str(unit.get("id") or f"script-{unit_index:02d}")
            is_avatar_only = _is_avatar_only_voiceover_unit(scene, unit, unit_index, len(units), production_format)
            has_mg_for_unit = (
                not is_avatar_only
                and production_format == "broll_html"
                and _mg_director_enabled(mg_director)
                and (not mg_unit_ids or unit_id in mg_unit_ids)
            )
            scene_role = AVATAR_ONLY if is_avatar_only else (BROLL_BACKDROP if has_mg_for_unit else FULL_BROLL)
            if has_mg_for_unit:
                mg_shot_indexes.append(len(shots) + 1)
            broll_prompt = "" if is_avatar_only else _asset_prompt_from_plan(asset_plan, narration)
            shots.append({
                "title": str(unit.get("title") or scene.get("title") or f"分镜 {scene_index}-{unit_index}"),
                "narration": narration,
                "duration_seconds": duration,
                "broll_prompt": broll_prompt,
                "scene_role": scene_role,
                "visual_role": _visual_role_for_scene_role(scene_role),
                "information_layer": _information_layer_from_mg_director(scene, mg_director, narration) if has_mg_for_unit else {},
                "asset_search_plan": {} if is_avatar_only else asset_plan,
                "mg_director": mg_director if has_mg_for_unit else {},
                "creative_scene_id": str(scene.get("id") or f"scene-{scene_index:02d}"),
                "voiceover_unit_id": unit_id,
            })
        if shots:
            html_layers = []
            if production_format == "broll_html" and _mg_director_enabled(mg_director) and mg_shot_indexes:
                html_layers.append({
                    "title": str(scene.get("title") or "HTML 信息层"),
                    "shot_indexes": mg_shot_indexes,
                    "description": str(mg_director.get("html_brief") or mg_director.get("story_goal") or mg_director.get("one_learning_point") or ""),
                    "mg_director": mg_director,
                    "style": {
                        "palette": _string_list((director_document or {}).get("html_mg_style", {}).get("palette") if isinstance((director_document or {}).get("html_mg_style"), dict) else None, ["#22D3EE", "#F8FAFC", "#0F172A"]),
                        "typography": "无衬线粗标题 + 关键信息块",
                        "motion": _mg_timeline_summary({"timeline": mg_director.get("timeline") if isinstance(mg_director.get("timeline"), list) else []}),
                    },
                    "timing": {
                        "scope": str(mg_director.get("scope") or ("cross_shot" if len(mg_shot_indexes) > 1 else "single_shot")),
                        "bound_voiceover_unit_ids": [str(item) for item in mg_director.get("bound_voiceover_unit_ids", []) if str(item).strip()],
                        "cross_shot_reason": str(mg_director.get("story_goal") or ""),
                    },
                    "safe_area": "avoid_caption_and_host_right_avatar",
                })
            groups.append({
                "title": str(scene.get("title") or f"场景 {scene_index}"),
                "intent": str(scene.get("director_note") or mg_director.get("story_goal") or ""),
                "shots": shots,
                "html_layers": html_layers,
            })
    if not groups:
        raise VideoStudioGenerationError("创作规划书缺少可生成分镜的 scenes")
    return normalize_scene_groups(groups, production_format, director_document)


