def normalize_producer_analysis(analysis: Dict[str, Any], topic: str) -> Dict[str, Any]:
    assessment = analysis.get("input_assessment") if isinstance(analysis.get("input_assessment"), dict) else {}
    availability = analysis.get("asset_availability") if isinstance(analysis.get("asset_availability"), dict) else {}
    options = analysis.get("production_options") if isinstance(analysis.get("production_options"), list) else []
    normalized_options = []
    for index, raw_option in enumerate(options[:4], start=1):
        if not isinstance(raw_option, dict):
            continue
        option_id = str(raw_option.get("id") or chr(64 + index)).strip() or chr(64 + index)
        production_format = str(raw_option.get("production_format") or ("broll_html" if option_id.upper() == "B" else "broll"))
        if production_format not in {"broll", "broll_html"}:
            production_format = "broll_html"
        normalized_options.append({
            "id": option_id,
            "label": str(raw_option.get("label") or ("B-roll + HTML 信息层" if production_format == "broll_html" else "纯 B-roll")),
            "production_format": production_format,
            "summary": str(raw_option.get("summary") or ""),
            "recommended": bool(raw_option.get("recommended")),
            "reason": str(raw_option.get("reason") or ""),
        })
    if not normalized_options:
        normalized_options = [
            {
                "id": "A",
                "label": "纯 B-roll",
                "production_format": "broll",
                "summary": "以真实素材和字幕为主，制作速度快。",
                "recommended": False,
                "reason": "适合低信息密度或强现场感主题。",
            },
            {
                "id": "B",
                "label": "B-roll + HTML 信息层",
                "production_format": "broll_html",
                "summary": "用素材承载语境，用 HTML/MG 承载数据、因果和时间线。",
                "recommended": True,
                "reason": "更适合长视频解释复杂主题。",
            },
        ]
    recommended_id = str(analysis.get("recommended_option_id") or "")
    if not recommended_id:
        recommended = next((option for option in normalized_options if option.get("recommended")), normalized_options[-1])
        recommended_id = str(recommended.get("id") or "B")
    return {
        "version": "producer_analysis_v1",
        "input_assessment": {
            "input_type": str(assessment.get("input_type") or "主题"),
            "confidence": str(assessment.get("confidence") or "medium"),
            "summary": str(assessment.get("summary") or f"可以围绕“{topic}”生成长视频生产方案。"),
        },
        "topic_blocks": _normalize_topic_blocks(analysis.get("topic_blocks"), topic),
        "key_data_scenes": _normalize_key_data_scenes(analysis.get("key_data_scenes"), topic),
        "asset_availability": {
            "local_material_check": str(availability.get("local_material_check") or "当前未检测到用户本地素材，优先从免费素材库检索。"),
            "open_asset_keywords": _string_list(availability.get("open_asset_keywords"), _topic_keywords(topic)[:4]),
            "risk_notes": _string_list(availability.get("risk_notes"), ["关键数据和历史表述需要在成片前核验。"]),
        },
        "production_options": normalized_options,
        "recommended_option_id": recommended_id,
    }


