def _creator_mg_pattern_for_shot(
    raw_shot: Dict[str, Any],
    shot_id: str,
    narration: str,
    prompt: str,
    scene_role: str,
) -> Dict[str, Any]:
    if scene_role != BROLL_BACKDROP:
        return {}
    info = raw_shot.get("information_layer") if isinstance(raw_shot.get("information_layer"), dict) else {}
    mg_director = raw_shot.get("mg_director") if isinstance(raw_shot.get("mg_director"), dict) else {}
    asset_plan = raw_shot.get("asset_search_plan") if isinstance(raw_shot.get("asset_search_plan"), dict) else {}
    text = " ".join(
        [
            str(raw_shot.get("title") or ""),
            narration,
            prompt,
            str(info.get("overlay_type") or ""),
            str(mg_director.get("visual_system") or ""),
            str(mg_director.get("story_goal") or ""),
            str(mg_director.get("html_brief") or ""),
            str(mg_director.get("main_visual_metaphor") or ""),
        ]
    ).lower()
    overlay_type = str(info.get("overlay_type") or "").strip()
    visual_system = str(mg_director.get("visual_system") or "").strip().lower()
    pattern_id = "single_claim_lockup"
    if overlay_type == "metric_callout" or visual_system == "metric" or re.search(r"\d|%|倍|亿|万|指数|排名|数据|增长|下降", text):
        pattern_id = "data_callout"
    if overlay_type == "causal_chain" or visual_system in {"causal", "process"} or any(token in text for token in ["因为", "导致", "机制", "链路", "因果", "结果", "出清", "修复"]):
        pattern_id = "process_map"
    if overlay_type == "route_trace" or visual_system == "route" or any(token in text for token in ["路径", "路线", "流向", "迁移", "传导"]):
        pattern_id = "process_map"
    if visual_system == "timeline" or any(token in text for token in ["时间线", "阶段", "随后", "最后", "年代", "历史", "长期"]):
        pattern_id = "timeline_evidence"
    if visual_system == "comparison" or any(token in text for token in ["对比", "相比", "前后", "一边", "另一边", "差异"]):
        pattern_id = "comparison_split"
    if overlay_type in {"field_labels", "keyword_stamp"} or visual_system == "reveal" or any(token in text for token in ["揭示", "焦点", "关键词", "标签"]):
        pattern_id = "focus_reveal"
    if any(token in text for token in ["报告", "论文", "研究", "新闻", "档案", "来源", "引用", "证据"]):
        pattern_id = "source_citation"
    if any(token in text for token in ["案例", "样本", "多个", "三类", "三个", "二是", "第二"]):
        pattern_id = "multi_case_evidence"

    catalog_item = CREATOR_MG_PATTERN_CATALOG[pattern_id]
    pattern = {
        "id": pattern_id,
        "label": catalog_item["label"],
        "intent": catalog_item["intent"],
        "reason": _creator_mg_pattern_reason(pattern_id, overlay_type, visual_system),
        "expression_contract": {
            "role": "B-roll 先提供真实语境，HTML/MG 再承载结构化信息。",
            "html_usage": "AI HTML 可按该表达框架自由生成，不绑定固定模板。",
            "broll_usage": "优先选择能填入素材槽位的镜头，再考虑氛围补充。",
        },
        "advanced_effects": _creator_mg_advanced_effects(catalog_item.get("advanced_effects", [])),
        "asset_slots": _creator_pattern_asset_slots(pattern_id, shot_id, prompt, narration, asset_plan),
    }
    return pattern


def _creator_mg_pattern_reason(pattern_id: str, overlay_type: str, visual_system: str) -> str:
    signals = [item for item in [overlay_type, visual_system] if item]
    if signals:
        return f"根据信息层/导演信号 {' + '.join(signals)} 选择 {CREATOR_MG_PATTERN_CATALOG[pattern_id]['label']}。"
    return f"根据口播和素材描述选择 {CREATOR_MG_PATTERN_CATALOG[pattern_id]['label']}。"


