def _creator_pattern_asset_slots(
    pattern_id: str,
    shot_id: str,
    prompt: str,
    narration: str,
    asset_search_plan: Dict[str, Any],
) -> List[Dict[str, Any]]:
    catalog_item = CREATOR_MG_PATTERN_CATALOG.get(pattern_id, CREATOR_MG_PATTERN_CATALOG["single_claim_lockup"])
    base_queries = _broll_search_queries(asset_search_plan.get("search_queries"), fallback=[prompt, narration])
    named_entities = _string_list(asset_search_plan.get("named_entities"), [])
    summary = _compact_broll_query(asset_search_plan.get("summary") or "")
    candidates = [*base_queries, _compact_broll_query(prompt), summary, _compact_broll_query(narration)]
    context_query = next((item for item in candidates if _prompt_text(item)), _compact_broll_query(prompt or narration))
    entity_suffix = " ".join(named_entities[:3])
    slots: List[Dict[str, Any]] = []
    for index, title in enumerate(catalog_item.get("slot_titles", [])[:2], start=1):
        query_parts = [_prompt_text(context_query)]
        if entity_suffix:
            query_parts.append(entity_suffix)
        if pattern_id == "data_callout":
            query_parts.append("data chart documentary footage")
        elif pattern_id == "source_citation":
            query_parts.append("report archive document")
        elif pattern_id == "comparison_split":
            query_parts.append("comparison before after")
        elif pattern_id == "timeline_evidence":
            query_parts.append("historical archive timeline")
        elif pattern_id == "process_map":
            query_parts.append("process mechanism documentary")
        elif pattern_id == "multi_case_evidence":
            query_parts.append("case examples montage")
        elif pattern_id == "focus_reveal":
            query_parts.append("close up reveal detail")
        else:
            query_parts.append("documentary context")
        query = _compact_broll_query(" ".join(part for part in query_parts if part), max_chars=96, max_terms=12)
        slots.append(
            {
                "id": f"{shot_id}:creator-mg-slot-{index}",
                "title": str(title),
                "query": query,
                "role": "context" if index == 1 else "evidence",
                "usage_rule": "用于支撑当前 MG 表达框架，可作为背景 B-roll 或嵌入 HTML 信息层的视觉证据。",
            }
        )
    return slots


def _asset_slots_for_shot(shot: Dict[str, Any]) -> List[Dict[str, Any]]:
    options = shot.get("broll_options") if isinstance(shot.get("broll_options"), list) else []
    slots = []
    for index, option in enumerate(options[:8], start=1):
        if not isinstance(option, dict):
            continue
        slots.append({
            "id": f"{shot.get('id')}:broll-candidate-{index}",
            "kind": "broll_candidate",
            "title": str(option.get("title") or f"素材方案 {index}"),
            "search_query": str(option.get("search_query") or shot.get("broll_prompt") or ""),
            "duration_seconds": _positive_float(option.get("duration_seconds"), _positive_float(shot.get("duration_seconds"), 6.0)),
            "asset_url": str(option.get("asset_url") or ""),
            "asset_path": str(option.get("asset_path") or ""),
            "usage_rule": "B-roll is full-frame background; do not embed as HTML video.",
        })
    creator_pattern = shot.get("creator_mg_pattern") if isinstance(shot.get("creator_mg_pattern"), dict) else {}
    for index, slot in enumerate(creator_pattern.get("asset_slots") if isinstance(creator_pattern.get("asset_slots"), list) else [], start=1):
        if not isinstance(slot, dict):
            continue
        slots.append({
            "id": str(slot.get("id") or f"{shot.get('id')}:creator-mg-slot-{index}"),
            "kind": "creator_mg_asset_slot",
            "title": str(slot.get("title") or f"MG 素材槽 {index}"),
            "search_query": str(slot.get("query") or shot.get("broll_prompt") or ""),
            "duration_seconds": _positive_float(shot.get("duration_seconds"), 6.0),
            "asset_url": "",
            "asset_path": "",
            "usage_rule": str(slot.get("usage_rule") or "This asset can be embedded in the creator MG HTML frame or used as guided B-roll."),
        })
    return slots


def _avatar_rect(width: int, height: int) -> List[int]:
    preferred_ratio = 0.17 if height > width else 0.12
    size = max(120, min(int(round(width * preferred_ratio)), int(round(width * 0.22))))
    margin_x = max(18, int(round(width * 0.035)))
    margin_bottom = max(18, int(round(height * 0.035)))
    return [width - size - margin_x, height - size - margin_bottom, width - margin_x, height - margin_bottom]


def _subtitle_rect(width: int, height: int, avatar_rect: List[int]) -> List[int]:
    bottom = height - int(height * 0.035)
    top = bottom - max(56, int(height * 0.08))
    left = int(width * 0.06)
    right = max(left + 1, avatar_rect[0] - int(width * 0.03))
    return [left, top, right, bottom]


def _hydrate_group_timing(groups: List[Dict[str, Any]], director_document: Dict[str, Any] | None = None) -> List[Dict[str, Any]]:
    current = 0.0
    html_director = _html_motion_director_from_document(director_document)
    hydrated: List[Dict[str, Any]] = []
    for group in groups:
        updated_group = {**group}
        shots = []
        for shot in group.get("shots", []):
            if not isinstance(shot, dict):
                continue
            updated_shot = dict(shot)
            _attach_render_contract(updated_shot, current, html_director)
            current += float(updated_shot.get("duration_seconds") or 0)
            shots.append(updated_shot)
        updated_group["shots"] = shots
        if str(updated_group.get("id") or "") and isinstance(updated_group.get("html_layers"), list):
            updated_group["html_layers"] = _hydrate_html_layers_from_shots(updated_group["html_layers"], shots)
        hydrated.append(updated_group)
    return hydrated


def _html_motion_director_from_document(director_document: Dict[str, Any] | None) -> Dict[str, Any]:
    if isinstance(director_document, dict) and isinstance(director_document.get("html_motion_director"), dict):
        return _normalize_html_motion_director(director_document.get("html_motion_director"), str(director_document.get("title") or ""))
    return _normalize_html_motion_director({}, "")


def _hydrate_html_layers_from_shots(layers: List[Any], shots: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    by_id = {str(shot.get("id") or ""): shot for shot in shots if isinstance(shot, dict)}
    hydrated: List[Dict[str, Any]] = []
    for layer in layers:
        if not isinstance(layer, dict):
            continue
        shot_ids = [str(item) for item in layer.get("shot_ids", []) if str(item)]
        layer_shots = [by_id[shot_id] for shot_id in shot_ids if shot_id in by_id]
        first_shot = next((by_id[shot_id] for shot_id in shot_ids if shot_id in by_id), None)
        mg_director = layer.get("mg_director") if isinstance(layer.get("mg_director"), dict) else (
            first_shot.get("mg_director") if isinstance(first_shot, dict) and isinstance(first_shot.get("mg_director"), dict) else {}
        )
        mg_clip = _mg_clip_for_html_layer({**layer, "shot_ids": shot_ids}, layer_shots) if layer_shots else {}
        hydrated.append(
            {
                **layer,
                "mg_director": mg_director,
                "description": str(
                    layer.get("description")
                    or mg_director.get("html_brief")
                    or mg_director.get("story_goal")
                    or ""
                ),
                "template_id": str(first_shot.get("template_id") or "") if isinstance(first_shot, dict) else "",
                "template_family": str(first_shot.get("template_family") or "") if isinstance(first_shot, dict) else "",
                "motion_timing": first_shot.get("motion_timing") if isinstance(first_shot, dict) else {},
                "timeline_elements": first_shot.get("timeline_elements") if isinstance(first_shot, dict) else [],
                "mg_clip": mg_clip if mg_clip else (_mg_clip_for_shot(first_shot) if isinstance(first_shot, dict) and _shot_uses_html(first_shot) else {}),
            }
        )
    return hydrated


def _attach_render_contract(shot: Dict[str, Any], start_seconds: float, html_director: Dict[str, Any] | None = None) -> None:
    scene_role = str(shot.get("scene_role") or FULL_BROLL)
    duration = float(_positive_int(shot.get("duration_seconds"), 6))
    end_seconds = start_seconds + duration
    info = shot.get("information_layer") if isinstance(shot.get("information_layer"), dict) else {}
    html_director = html_director if isinstance(html_director, dict) else _normalize_html_motion_director({}, "")
    if scene_role != BROLL_BACKDROP or not _mg_director_enabled(shot.get("mg_director")):
        shot.update(
            {
                "start_seconds": round(start_seconds, 3),
                "end_seconds": round(end_seconds, 3),
                "html_render_strategy": "none",
                "template_id": "",
                "template_fallback_id": "",
                "template_family": "none",
                "slot_count": 0,
                "slot_schema": [],
                "requires_asset": False,
                "requires_path_motion": False,
                "motion_timing": _motion_timing(duration, 0, scene_role),
                "micro_beats": [],
                "composition_beats": [],
                "html_design": {},
                "bespoke_html_prompt": "",
                "visual_groups": _visual_groups(scene_role, info),
                "timeline_elements": _timeline_elements(str(shot.get("id") or ""), start_seconds, end_seconds, scene_role, str(shot.get("visual_role") or "broll_primary")),
                "html_contract_summary": (
                    "纯数字人镜头：不生成 B-roll/HTML，只保留数字人口播和字幕轨。"
                    if scene_role == AVATAR_ONLY
                    else ("纯 B-roll 镜头：不生成 HTML 信息层，只保留素材、数字人和字幕轨。" if scene_role != BROLL_BACKDROP else "缺少 MG 导演：不生成 HTML 信息层。")
                ),
            }
        )
        return

    render_strategy = str(html_director.get("render_strategy") or "llm_bespoke_html")
    if render_strategy not in {"llm_bespoke_html", "template"}:
        render_strategy = "llm_bespoke_html"
    template = _template_contract_for_information_layer(info, shot) if render_strategy == "template" else _optional_template_contract_for_information_layer(info, shot)
    slot_count = int(template.get("slot_count") or 1)
    timing = _motion_timing(duration, slot_count, scene_role, html_director)
    micro_beats = _micro_beats(info, timing, duration, slot_count)
    composition_beats = _composition_beats(info, micro_beats)
    html_design = _html_design_for_shot(shot, info, html_director, render_strategy)
    existing_html_design = shot.get("html_design") if isinstance(shot.get("html_design"), dict) else {}
    for key in ("custom_html", "custom_css", "ai_html_generation"):
        if existing_html_design.get(key):
            html_design[key] = existing_html_design[key]
    bespoke_prompt = _bespoke_html_prompt_for_shot(shot, info, html_director, html_design, micro_beats)
    mg_clip = _mg_clip_for_shot(
        {
            **shot,
            "html_design": html_design,
            "html_render_strategy": render_strategy,
            **template,
            "motion_timing": timing,
            "bespoke_html_prompt": bespoke_prompt,
        }
    )
    shot.update(
        {
            "start_seconds": round(start_seconds, 3),
            "end_seconds": round(end_seconds, 3),
            "html_render_strategy": render_strategy,
            **template,
            "motion_timing": timing,
            "micro_beats": micro_beats,
            "composition_beats": composition_beats,
            "html_design": html_design,
            "mg_clip": mg_clip,
            "bespoke_html_prompt": bespoke_prompt,
            "visual_groups": _visual_groups(scene_role, info),
            "timeline_elements": _timeline_elements(str(shot.get("id") or ""), start_seconds, end_seconds, scene_role, str(shot.get("visual_role") or "hybrid_broll_html")),
        }
    )
    shot["html_contract_summary"] = _html_contract_summary(shot)


def _optional_template_contract_for_information_layer(info: Dict[str, Any], shot: Dict[str, Any]) -> Dict[str, Any]:
    contract = _template_contract_for_information_layer(info, shot)
    return {
        **contract,
        "template_id": "",
        "template_family": f"optional_{contract['template_family']}",
        "template_fallback_id": contract["template_id"],
    }


def _template_contract_for_information_layer(info: Dict[str, Any], shot: Dict[str, Any]) -> Dict[str, Any]:
    overlay_type = str(info.get("overlay_type") or "field_labels")
    items = info.get("items") if isinstance(info.get("items"), list) else []
    if overlay_type == "metric_callout" and len(items) <= 1:
        template_id = "single-metric-lock"
    elif overlay_type == "metric_callout":
        template_id = "claim-metric-bars"
    elif overlay_type == "route_trace":
        template_id = "route-node-lock"
    elif overlay_type == "causal_chain":
        template_id = "causal-node-web"
    elif overlay_type == "keyword_stamp":
        template_id = "single-claim-lock"
    else:
        template_id = "evidence-card-rail"
    catalog = MOTION_TEMPLATE_CATALOG[template_id]
    schema = catalog["slot_schema"]
    if template_id.startswith("single-"):
        slot_count = 1
    else:
        slot_count = max(2, min(5, len(items) or len(_clauses(str(shot.get("narration") or ""), 3)) or 2))
    return {
        "template_id": template_id,
        "template_family": catalog["template_family"],
        "slot_count": slot_count,
        "slot_schema": schema,
        "requires_asset": catalog["requires_asset"],
        "requires_path_motion": catalog["requires_path_motion"],
    }


def _motion_timing(duration: float, slot_count: int, scene_role: str, html_director: Dict[str, Any] | None = None) -> Dict[str, Any]:
    safe_duration = max(1.0, float(duration or 0))
    director_timing = html_director.get("timing_principles") if isinstance(html_director, dict) and isinstance(html_director.get("timing_principles"), dict) else {}
    if safe_duration < 5.5:
        mode = "short"
        enter_ratio, build_ratio, exit_ratio = 0.12, 0.50, 0.12
    elif safe_duration > 9.0:
        mode = "long"
        enter_ratio, build_ratio, exit_ratio = 0.14, 0.58, 0.12
    else:
        mode = "standard"
        enter_ratio, build_ratio, exit_ratio = 0.16, 0.43, 0.16
    if scene_role == BROLL_BACKDROP:
        build_ratio = min(0.62, build_ratio + 0.05)
        exit_ratio = max(0.10, exit_ratio - 0.02)
    count = max(0, min(5, int(slot_count or 0)))
    enter_s = round(min(safe_duration * 0.35, _positive_float(director_timing.get("enter_s"), safe_duration * enter_ratio)), 3)
    build_s = round(min(safe_duration * 0.72, _positive_float(director_timing.get("build_s"), safe_duration * build_ratio)), 3)
    exit_s = round(min(safe_duration * 0.25, _positive_float(director_timing.get("exit_s"), safe_duration * exit_ratio)), 3)
    hold_s = round(max(0.4, safe_duration - enter_s - build_s - exit_s), 3)
    phase_times = []
    if count:
        base = enter_s
        span = max(0.2, build_s)
        denominator = max(1, count - 1)
        phase_times = [round(base + (span * idx / denominator if denominator else 0), 3) for idx in range(count)]
    return {
        "duration_mode": mode,
        "duration_seconds": round(safe_duration, 3),
        "enter_ratio": enter_ratio,
        "build_ratio": build_ratio,
        "exit_ratio": exit_ratio,
        "enter_s": enter_s,
        "build_s": build_s,
        "hold_s": hold_s,
        "exit_s": exit_s,
        "slot_count": count,
        "phase_times": phase_times,
    }


def _html_design_for_shot(
    shot: Dict[str, Any],
    info: Dict[str, Any],
    html_director: Dict[str, Any],
    render_strategy: str,
) -> Dict[str, Any]:
    policy = html_director.get("bespoke_html_policy") if isinstance(html_director.get("bespoke_html_policy"), dict) else {}
    mg_director = shot.get("mg_director") if isinstance(shot.get("mg_director"), dict) else {}
    creator_pattern = shot.get("creator_mg_pattern") if isinstance(shot.get("creator_mg_pattern"), dict) else {}
    if not _mg_director_enabled(mg_director):
        raise VideoStudioGenerationError("缺少 MG 导演层，不能生成 HTML 设计")
    content_slots = _html_content_slots_from_mg_director(mg_director)
    if not content_slots:
        raise VideoStudioGenerationError("MG 导演层缺少 screen_slots，不能生成 HTML 设计")
    illustration_plan = _html_illustration_plan_for_shot(shot, html_director, content_slots, mg_director)
    motion_sequence = _html_motion_sequence_from_mg_director(mg_director)
    visual_system = _normalize_mg_visual_system(mg_director.get("visual_system")) or "comparison"
    illustration_plan["visual_system"] = visual_system
    design_contract = _normalize_design_contract(
        None,
        shot,
        visual_system,
        {
            "layout": str(illustration_plan.get("layout") or ""),
            "illustration": str(illustration_plan.get("metaphor") or ""),
            "motion": _mg_timeline_summary({"timeline": motion_sequence}),
        },
        [],
        motion_sequence,
        information_layer={},
        illustration_plan=illustration_plan,
        content_slots=content_slots,
        duration_seconds=_positive_float(shot.get("duration_seconds"), 6.0),
    )
    return {
        "version": "html_scene_design_v1",
        "render_strategy": render_strategy,
        "overlay_mode": _documentary_overlay_mode(
            None,
            " ".join([
                str(shot.get("title") or ""),
                str(mg_director.get("story_goal") or ""),
                str(mg_director.get("html_brief") or ""),
            ]),
        ),
        "visual_system": visual_system,
        "visual_language": str(html_director.get("visual_language") or ""),
        "art_direction": DOCUMENTARY_OVERLAY_ART_DIRECTION,
        "layout_principles": html_director.get("layout_principles") if isinstance(html_director.get("layout_principles"), list) else [],
        "one_learning_point": _prompt_text(mg_director.get("one_learning_point") or ""),
        "central_visual_idea": _prompt_text(mg_director.get("main_visual_metaphor") or illustration_plan.get("subject") or ""),
        "creator_mg_pattern": creator_pattern,
        "advanced_effects": creator_pattern.get("advanced_effects") if isinstance(creator_pattern.get("advanced_effects"), list) else [],
        "screen_text_policy": _prompt_text(
            "屏幕文字只能来自 MG 导演层 screen_slots，不得从口播、information_layer 或历史 HTML 设计扩写。"
        ),
        "html_scope": str(policy.get("html_scope") or "single_scene_overlay"),
        "css_motion": str(policy.get("css_motion") or "CSS keyframes + timeline variables"),
        "safe_area": {
            "avoid_avatar": True,
            "avoid_caption": True,
            "preferred_region": "full_frame_except_caption_and_small_avatar_box",
        },
        "visual_brief": (
            f"为分镜“{shot.get('title')}”设计一层可独立渲染的 HTML 信息图。"
            f"MG视觉系统：{visual_system}。"
            f"MG导演目标：{mg_director.get('story_goal') or ''}。"
            f"核心问题：{mg_director.get('core_question') or ''}。"
            f"插画主体：{illustration_plan.get('subject')}；视觉隐喻：{illustration_plan.get('metaphor')}。"
            f"HTML brief：{mg_director.get('html_brief') or ''}"
        ),
        "illustration_plan": illustration_plan,
        "motion_sequence": motion_sequence,
        "content_slots": content_slots,
        "design_contract": design_contract,
    }


def _html_illustration_plan_for_shot(
    shot: Dict[str, Any],
    html_director: Dict[str, Any],
    content_slots: List[Dict[str, Any]],
    mg_director: Dict[str, Any],
) -> Dict[str, Any]:
    visual_system = _normalize_mg_visual_system(mg_director.get("visual_system")) or "comparison"
    layout_by_system = {
        "metric": "metric_spine",
        "causal": "causal_cascade",
        "route": "route_arc",
        "timeline": "timeline_ridge",
        "comparison": "before_after_slider",
        "reveal": "scan_reveal",
    }
    shape_by_system = {
        "metric": ["measure_axis", "metric_lockup", "threshold_line"],
        "causal": ["cause_node", "connector_path", "effect_node"],
        "route": ["map_grid", "route_path", "anchor_pin"],
        "timeline": ["time_axis", "stage_marker", "event_label"],
        "comparison": ["left_state", "scan_divider", "right_state"],
        "reveal": ["scan_mask", "evidence_texture", "focus_frame"],
    }
    keyword = _prompt_text(mg_director.get("one_learning_point") or shot.get("title") or "关键信息")
    primary_fact = _prompt_text((mg_director.get("supporting_metric") or {}).get("text") if isinstance(mg_director.get("supporting_metric"), dict) else "")
    takeaway = _prompt_text(mg_director.get("one_learning_point") or keyword)
    palette = ["#22D3EE", "#F8FAFC", "#0F172A", "#A7F3D0"]
    style = html_director.get("html_mg_style") if isinstance(html_director.get("html_mg_style"), dict) else {}
    if isinstance(style.get("palette"), list) and style.get("palette"):
        palette = [str(color) for color in style.get("palette")[:4]]
    shapes_for_system = shape_by_system.get(visual_system, shape_by_system["comparison"])
    shapes = [
        {
            "role": "hero",
            "label": keyword,
            "shape": shapes_for_system[0],
        },
        {
            "role": "primary_fact",
            "label": primary_fact,
            "shape": shapes_for_system[1],
        },
        {
            "role": "takeaway",
            "label": takeaway,
            "shape": shapes_for_system[2],
        },
    ]
    for slot in content_slots[:3]:
        role = str(slot.get("role") or "")
        if role.startswith("module_"):
            shapes.append({
                "role": role,
                "label": _prompt_text(slot.get("label") or slot.get("text") or role),
                "shape": "info_node",
            })
    return {
        "mode": "drawn_html_overlay",
        "visual_system": visual_system,
        "subject": _prompt_text(mg_director.get("main_visual_metaphor") or keyword),
        "metaphor": _prompt_text(mg_director.get("main_visual_metaphor") or mg_director.get("html_brief") or keyword),
        "layout": layout_by_system.get(visual_system, "before_after_slider"),
        "palette": palette,
        "shapes": shapes[:6],
        "text_blocks": [
            {"role": str(slot.get("role") or ""), "text": _prompt_text(slot.get("text") or slot.get("label") or "")}
            for slot in content_slots
            if slot.get("text") or slot.get("label")
        ][:6],
    }


def _html_content_slots_from_mg_director(mg_director: Dict[str, Any] | None) -> List[Dict[str, Any]]:
    raw = mg_director if isinstance(mg_director, dict) else {}
    slots = raw.get("screen_slots") if isinstance(raw.get("screen_slots"), list) else []
    compacted: List[Dict[str, Any]] = []
    seen: List[str] = []
    for item in slots[:5]:
        if not isinstance(item, dict):
            continue
        text = _screen_text_phrase(item.get("text") or "", limit=28, seen_keys=seen)
        if not text:
            continue
        seen.append(text)
        slot: Dict[str, Any] = {"role": str(item.get("role") or "label"), "text": text}
        label = _screen_text_phrase(item.get("label") or "", limit=10)
        if label:
            slot["label"] = label
        compacted.append(slot)
    return compacted


def _html_motion_sequence_from_mg_director(mg_director: Dict[str, Any] | None) -> List[Dict[str, Any]]:
    raw = mg_director if isinstance(mg_director, dict) else {}
    timeline = raw.get("timeline") if isinstance(raw.get("timeline"), list) else []
    items: List[Dict[str, Any]] = []
    for item in timeline[:8]:
        if not isinstance(item, dict):
            continue
        items.append(
            {
                "at_s": _positive_float(item.get("start_s") if item.get("start_s") is not None else item.get("at_s"), 0.0),
                "target": str(item.get("target") or "main_visual"),
                "action": str(item.get("action") or item.get("motion") or "reveal"),
                "text": _screen_text_phrase(item.get("text") or "", limit=28),
                "duration_s": round(max(0.0, _positive_float(item.get("end_s"), 0.0) - _positive_float(item.get("start_s"), 0.0)), 3) if item.get("end_s") is not None else None,
            }
        )
    return items


def _mg_contract_canvas() -> Dict[str, Any]:
    avatar = _avatar_rect(DEFAULT_RENDER_WIDTH, DEFAULT_RENDER_HEIGHT)
    return {
        "width": DEFAULT_RENDER_WIDTH,
        "height": DEFAULT_RENDER_HEIGHT,
        "safe_top": 72,
        "safe_bottom": 160,
        "safe_left": 96,
        "safe_right": 96,
        "avatar_reserved": {"x": avatar[0], "y": avatar[1], "w": avatar[2] - avatar[0], "h": avatar[3] - avatar[1]},
    }


def _mg_contract_canvas_from_raw(value: Any) -> Dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    base = _mg_contract_canvas()

    def number(key: str, fallback: int, minimum: int, maximum: int) -> int:
        try:
            parsed = int(round(float(raw.get(key))))
        except (TypeError, ValueError):
            parsed = fallback
        return max(minimum, min(maximum, parsed))

    avatar_raw = raw.get("avatar_reserved") if isinstance(raw.get("avatar_reserved"), dict) else {}
    avatar_base = base["avatar_reserved"]
    avatar_rect = _rect_from_raw(avatar_raw, avatar_base)
    return {
        "width": number("width", DEFAULT_RENDER_WIDTH, 1280, 3840),
        "height": number("height", DEFAULT_RENDER_HEIGHT, 720, 2160),
        "safe_top": number("safe_top", base["safe_top"], 0, 260),
        "safe_bottom": number("safe_bottom", base["safe_bottom"], 80, 360),
        "safe_left": number("safe_left", base["safe_left"], 0, 260),
        "safe_right": number("safe_right", base["safe_right"], 0, 360),
        "avatar_reserved": avatar_rect,
    }


def _mg_contract_layers() -> List[Dict[str, Any]]:
    return [
        {"id": "background", "z": 0, "role": "transparent"},
        {"id": "illustration", "z": 10, "role": "svg"},
        {"id": "labels", "z": 20, "role": "text"},
        {"id": "motion_focus", "z": 30, "role": "highlight"},
    ]


def _mg_contract_layout(visual_system: str, layout_hint: str = "") -> str:
    hint = str(layout_hint or "").lower()
    if visual_system == "metric":
        return "metric_spine"
    if visual_system == "causal":
        return "causal_cascade"
    if visual_system == "route":
        return "route_arc"
    if visual_system == "timeline":
        return "timeline_ridge"
    if any(token in hint for token in ("split", "slider", "before", "after", "左右", "对比", "前后")):
        return "before_after_slider"
    return "comparison_dashboard"


def _rect_from_raw(value: Any, fallback: Dict[str, int]) -> Dict[str, int]:
    raw = value if isinstance(value, dict) else {}

    def number(key: str, fallback_value: int, minimum: int, maximum: int) -> int:
        try:
            parsed = int(round(float(raw.get(key))))
        except (TypeError, ValueError):
            parsed = fallback_value
        return max(minimum, min(maximum, parsed))

    x = number("x", fallback["x"], 0, DEFAULT_RENDER_WIDTH - 48)
    y = number("y", fallback["y"], 0, DEFAULT_RENDER_HEIGHT - 48)
    w = number("w", fallback["w"], 48, DEFAULT_RENDER_WIDTH - x)
    h = number("h", fallback["h"], 32, DEFAULT_RENDER_HEIGHT - y)
    return {"x": x, "y": y, "w": w, "h": h}


def _mg_contract_element(
    element_id: str,
    element_type: str,
    rect: Dict[str, int],
    *,
    text: str = "",
    semantic: str = "",
    style_role: str = "",
    layer: str = "labels",
) -> Dict[str, Any]:
    element = {
        "id": element_id,
        "type": element_type,
        "rect": rect,
        "layer": layer,
    }
    if text:
        element["text"] = _prompt_text(text)
    if semantic:
        element["semantic"] = _prompt_text(semantic)
    if style_role:
        element["style_role"] = style_role
    return element


def _slot_text(slots: List[Dict[str, Any]], role: str, fallback: str = "") -> str:
    for slot in slots:
        if isinstance(slot, dict) and str(slot.get("role") or "") == role:
            return _prompt_text(slot.get("text") or slot.get("label") or fallback)
    return _prompt_text(fallback)


