def _mg_contract_timeline(
    timeline: List[Dict[str, Any]],
    elements: List[Dict[str, Any]],
    duration_seconds: float,
) -> List[Dict[str, Any]]:
    element_ids = {str(element.get("id") or "") for element in elements if isinstance(element, dict)}
    main_target = next(
        (
            str(element.get("id") or "")
            for element in elements
            if isinstance(element, dict) and str(element.get("id") or "") not in {"headline", "takeaway"}
        ),
        "headline",
    )
    aliases = {
        "metric": "primary_metric",
        "curve": "trend_path",
        "chain": "link_path",
        "map_grid": "route_map",
        "route": "route_path",
        "information_blocks": "module_1",
        "html": main_target,
        "illustration.hero": main_target,
        "primary_fact": "primary_metric" if "primary_metric" in element_ids else main_target,
        "data_badge": "primary_metric" if "primary_metric" in element_ids else main_target,
    }
    normalized: List[Dict[str, Any]] = []
    max_time = max(0.5, duration_seconds)
    for item in timeline[:8]:
        if not isinstance(item, dict):
            continue
        target = str(item.get("target") or "headline")
        if target not in element_ids:
            target = aliases.get(target, target)
        if target not in element_ids and "." in target:
            target = aliases.get(target.split(".")[-1], target.split(".")[-1])
        if target not in element_ids:
            target = main_target
        at_s = min(max_time, _positive_float(item.get("at_s"), 0.0) if item.get("at_s") not in {0, 0.0, "0", "0.0"} else 0.0)
        normalized.append({
            "at_s": round(at_s, 3),
            "target": target,
            "action": str(item.get("action") or item.get("motion") or "fade_slide_in"),
            "duration_s": round(min(1.4, max(0.25, _positive_float(item.get("duration_s"), 0.45))), 3),
            "text": _prompt_text(item.get("text") or ""),
        })
    if not normalized:
        normalized = [
            {"at_s": 0.0, "target": "headline", "action": "fade_slide_in", "duration_s": 0.35, "text": ""},
            {"at_s": 0.45, "target": main_target, "action": "draw_or_reveal", "duration_s": 0.8, "text": ""},
            {"at_s": min(max_time, 2.4), "target": "takeaway", "action": "lockup", "duration_s": 0.45, "text": ""},
        ]
    return normalized


def _normalize_design_contract(
    value: Any,
    raw_scene: Dict[str, Any],
    visual_system: str,
    html_design: Dict[str, Any],
    blocks: List[Dict[str, Any]],
    timeline: List[Dict[str, Any]],
    *,
    information_layer: Dict[str, Any] | None = None,
    illustration_plan: Dict[str, Any] | None = None,
    content_slots: List[Dict[str, Any]] | None = None,
    duration_seconds: float = 6.0,
) -> Dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    visual_system = _normalize_mg_visual_system(raw.get("visual_system") or visual_system) or "comparison"
    layout = str(raw.get("layout") or _mg_contract_layout(visual_system, html_design.get("layout") or html_design.get("illustration") or ""))
    info = information_layer if isinstance(information_layer, dict) else {}
    slots = content_slots if isinstance(content_slots, list) and content_slots else [
        {"role": "headline", "text": _prompt_text(info.get("keyword") or raw_scene.get("title") or "关键信息")},
        {"role": "primary_fact", "text": _prompt_text(info.get("primary_fact") or raw_scene.get("director_note") or raw_scene.get("title") or "")},
        *[
            {"role": f"module_{index}", "label": block.get("label"), "text": block.get("text")}
            for index, block in enumerate(blocks[:5], start=1)
            if isinstance(block, dict)
        ],
        {"role": "takeaway", "text": _prompt_text(info.get("takeaway") or raw_scene.get("director_note") or "")},
    ]
    illustration = illustration_plan if isinstance(illustration_plan, dict) else {
        "subject": str(html_design.get("illustration") or raw_scene.get("title") or ""),
        "metaphor": str(html_design.get("illustration") or raw_scene.get("director_note") or ""),
    }
    fallback_elements = _mg_contract_elements(
        layout=layout,
        visual_system=visual_system,
        title=str(raw_scene.get("title") or ""),
        logic=str(raw_scene.get("director_note") or html_design.get("motion") or ""),
        content_slots=slots,
        illustration_plan=illustration,
    )
    fallback_by_id = {str(element["id"]): element for element in fallback_elements}
    raw_elements = raw.get("elements") if isinstance(raw.get("elements"), list) else []
    elements: List[Dict[str, Any]] = []
    for index, item in enumerate(raw_elements[:8]):
        if not isinstance(item, dict):
            continue
        fallback = fallback_elements[min(index, len(fallback_elements) - 1)] if fallback_elements else {}
        element_id = str(item.get("id") or fallback.get("id") or f"element_{index + 1}")
        fallback_rect = (fallback_by_id.get(element_id) or fallback or {}).get("rect") if isinstance((fallback_by_id.get(element_id) or fallback), dict) else {}
        if not isinstance(fallback_rect, dict):
            fallback_rect = {"x": 120, "y": 120 + index * 96, "w": 640, "h": 86}
        elements.append({
            "id": element_id,
            "type": str(item.get("type") or fallback.get("type") or "text"),
            "rect": _rect_from_raw(item.get("rect"), fallback_rect),
            "layer": str(item.get("layer") or fallback.get("layer") or "labels"),
            "text": _prompt_text(item.get("text") or fallback.get("text") or ""),
            "semantic": _prompt_text(item.get("semantic") or fallback.get("semantic") or ""),
            "style_role": str(item.get("style_role") or fallback.get("style_role") or ""),
        })
    if not elements:
        elements = fallback_elements
    raw_timeline = raw.get("timeline") if isinstance(raw.get("timeline"), list) else timeline
    return {
        "version": "mg_design_contract_v1",
        "canvas": _mg_contract_canvas_from_raw(raw.get("canvas")),
        "visual_system": visual_system,
        "layout": layout,
        "layers": raw.get("layers") if isinstance(raw.get("layers"), list) and raw.get("layers") else _mg_contract_layers(),
        "elements": elements,
        "timeline": _mg_contract_timeline(raw_timeline, elements, duration_seconds),
        "acceptance": _string_list(
            raw.get("acceptance"),
            [
                "16:9 1920x1080 fixed coordinate system",
                "transparent or semi-transparent overlay",
                "do not cover caption safe area or avatar reserved area",
                "no generic card grid",
                "all text fits its rect",
            ],
        ),
    }


