def _micro_beats(info: Dict[str, Any], timing: Dict[str, Any], duration: float, slot_count: int) -> List[Dict[str, Any]]:
    beats: List[Dict[str, Any]] = []
    safe_duration = max(1.0, float(duration or 0))
    keyword = _prompt_text(info.get("keyword") or info.get("primary_fact") or "关键信息")
    beats.append({
        "at": 0.0,
        "time_s": 0.0,
        "role": "headline",
        "target": "headline",
        "text": keyword,
        "motion": "template_enter",
    })
    items = info.get("items") if isinstance(info.get("items"), list) else []
    phase_times = timing.get("phase_times") if isinstance(timing.get("phase_times"), list) else []
    for idx, item in enumerate(items[: max(1, min(5, slot_count))], start=1):
        if not isinstance(item, dict):
            continue
        time_s = float(phase_times[idx - 1]) if idx - 1 < len(phase_times) else float(timing.get("enter_s") or 0.5) + (idx - 1) * 0.35
        text = _prompt_text(item.get("text") or item.get("label") or "")
        beats.append({
            "at": round(min(0.9, time_s / safe_duration), 3),
            "time_s": round(time_s, 3),
            "role": "information_module",
            "target": f"module_{idx}",
            "text": text,
            "motion": "module_stagger_in",
        })
    takeaway_time = max(0.2, safe_duration - float(timing.get("exit_s") or 0.6) - 0.2)
    beats.append({
        "at": round(min(0.92, takeaway_time / safe_duration), 3),
        "time_s": round(takeaway_time, 3),
        "role": "locked_takeaway",
        "target": "takeaway",
        "text": _prompt_text(info.get("takeaway") or info.get("primary_fact") or keyword),
        "motion": "lock_takeaway",
    })
    return beats[:7]


def _composition_beats(info: Dict[str, Any], micro_beats: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    overlay_type = str(info.get("overlay_type") or "field_labels")
    return [
        {
            "at": beat.get("at"),
            "layer": "html",
            "role": beat.get("role"),
            "target": beat.get("target"),
            "text": beat.get("text"),
            "visual": overlay_type,
            "motion": beat.get("motion"),
        }
        for beat in micro_beats
    ]


def _visual_groups(scene_role: str, info: Dict[str, Any]) -> List[Dict[str, Any]]:
    uses_html = scene_role == BROLL_BACKDROP and bool(info.get("enabled"))
    groups: List[Dict[str, Any]] = []
    if scene_role != AVATAR_ONLY:
        groups.append(
            {
                "id": "broll",
                "layer": "broll",
                "role": "backdrop" if uses_html else "primary",
                "layout": "full_frame",
            }
        )
    groups.extend([
        {
            "id": "avatar",
            "layer": "avatar",
            "role": "primary_presenter" if scene_role == AVATAR_ONLY else "presenter",
            "layout": "center_stage" if scene_role == AVATAR_ONLY else "host_right",
        },
        {
            "id": "caption",
            "layer": "caption",
            "role": "subtitle",
            "layout": "bottom_safe_area",
        },
    ])
    if uses_html:
        groups.insert(
            1,
            {
                "id": "html-information",
                "layer": "html",
                "role": str(info.get("overlay_type") or "field_labels"),
                "layout": "full_frame_safe_area",
            },
        )
    return groups


def _timeline_elements(scene_id: str, start_seconds: float, end_seconds: float, scene_role: str, visual_role: str) -> List[Dict[str, Any]]:
    start = round(max(0.0, float(start_seconds or 0)), 3)
    end = round(max(start + 0.5, float(end_seconds or start + 0.5)), 3)
    duration = round(end - start, 3)
    base = {
        "scene_id": scene_id,
        "start": start,
        "duration": duration,
        "end": end,
        "visual_role": visual_role,
        "scene_role": scene_role,
    }
    elements: List[Dict[str, Any]] = []
    if scene_role != AVATAR_ONLY:
        elements.append(
            {
                **base,
                "id": f"scene:{scene_id}:broll",
                "type": "broll",
                "track_index": TIMELINE_TRACKS["broll"],
            }
        )
    if visual_role == "hybrid_broll_html":
        elements.append(
            {
                **base,
                "id": f"scene:{scene_id}:mg",
                "type": "mg_clip",
                "track_index": TIMELINE_TRACKS["mg_clip"],
            }
        )
    elements.extend(
        [
            {
                **base,
                "id": f"scene:{scene_id}:avatar",
                "type": "avatar",
                "track_index": TIMELINE_TRACKS["avatar"],
                "layout": "center_stage" if scene_role == AVATAR_ONLY else "host_right",
            },
            {
                **base,
                "id": f"scene:{scene_id}:caption",
                "type": "caption",
                "track_index": TIMELINE_TRACKS["caption"],
            },
        ]
    )
    return elements


def _html_contract_summary(shot: Dict[str, Any] | None) -> str:
    if not isinstance(shot, dict) or str(shot.get("scene_role") or "") != BROLL_BACKDROP:
        return ""
    timing = shot.get("motion_timing") if isinstance(shot.get("motion_timing"), dict) else {}
    tracks = [
        str(item.get("type") or "")
        for item in shot.get("timeline_elements", [])
        if isinstance(item, dict) and item.get("type")
    ]
    strategy = str(shot.get("html_render_strategy") or "llm_bespoke_html")
    if strategy == "template":
        strategy_text = f"Podcastor 编辑器模板 {shot.get('template_id')}"
    else:
        strategy_text = f"插画 HTML 计划，模板兜底 {shot.get('template_fallback_id') or 'none'}"
    return (
        f"{strategy_text}，{shot.get('slot_count')} 个信息槽；"
        f"入场 {timing.get('enter_s')}s，信息构建 {timing.get('build_s')}s，结论锁定后退场；"
        f"轨道：{' / '.join(tracks)}。"
    )


def _project_mg_clips(project: Dict[str, Any], shots: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    scene_groups = project.get("scene_groups") if isinstance(project.get("scene_groups"), list) else []
    editor_state = project.get("editor_state") if isinstance(project.get("editor_state"), dict) else {}
    design_doc_overrides = editor_state.get("mg_design_doc_overrides") if isinstance(editor_state.get("mg_design_doc_overrides"), dict) else {}
    candidates: List[Dict[str, Any]] = []
    candidates.extend(_mg_clips_from_html_layers(scene_groups, shots))
    if isinstance(project.get("mg_clips"), list):
        candidates.extend(project.get("mg_clips") or [])
    design_plan = project.get("design_plan") if isinstance(project.get("design_plan"), dict) else {}
    if isinstance(design_plan.get("mg_clips"), list):
        candidates.extend(design_plan.get("mg_clips") or [])
    render_manifest = project.get("render_manifest") if isinstance(project.get("render_manifest"), dict) else {}
    if isinstance(render_manifest.get("mg_clips"), list):
        candidates.extend(render_manifest.get("mg_clips") or [])

    clips: List[Dict[str, Any]] = []
    seen = set()
    for clip in candidates:
        if not isinstance(clip, dict):
            continue
        clip_id = str(clip.get("id") or "")
        if clip_id and clip_id in seen:
            continue
        if clip_id:
            seen.add(clip_id)
        if clip_id and isinstance(design_doc_overrides.get(clip_id), dict):
            clip = {**clip, "design_doc": design_doc_overrides[clip_id]}
        clips.append(clip)
    return clips


def _mg_clip_by_shot_from_project(project: Dict[str, Any], shots: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
    shot_ids = {str(shot.get("id") or "") for shot in shots if isinstance(shot, dict)}
    by_shot: Dict[str, Dict[str, Any]] = {}
    for clip in _project_mg_clips(project, shots):
        bound_shots = [str(item) for item in clip.get("bound_shots", []) if str(item)]
        if not bound_shots and clip.get("scene_id"):
            bound_shots = [str(clip.get("scene_id") or "")]
        for shot_id in bound_shots:
            if shot_id in shot_ids and shot_id not in by_shot:
                by_shot[shot_id] = clip
    return by_shot


def _build_video_studio_player_html(project: Dict[str, Any], *, page_label: str) -> str:
    topic = str(project.get("topic") or page_label)
    scene_groups = project.get("scene_groups") if isinstance(project.get("scene_groups"), list) else []
    editor_state = project.get("editor_state") if isinstance(project.get("editor_state"), dict) else {}
    selected_broll = editor_state.get("selected_broll_by_shot") if isinstance(editor_state.get("selected_broll_by_shot"), dict) else {}
    scripts = editor_state.get("shot_scripts") if isinstance(editor_state.get("shot_scripts"), dict) else {}
    voice_assets = editor_state.get("voice_assets_by_shot") if isinstance(editor_state.get("voice_assets_by_shot"), dict) else {}
    html_design_overrides = editor_state.get("html_design_overrides") if isinstance(editor_state.get("html_design_overrides"), dict) else {}
    avatar_enabled = bool(editor_state.get("avatar_enabled", True))
    bgm_enabled = bool(editor_state.get("bgm_enabled", True))
    bgm_volume = max(0.0, min(1.0, _positive_float(editor_state.get("bgm_volume"), 0.01)))
    selected_bgm_track = editor_state.get("selected_bgm_track") if isinstance(editor_state.get("selected_bgm_track"), dict) else {}
    bgm_url = str(selected_bgm_track.get("asset_url") or "") if bgm_enabled else ""
    bgm_title = str(selected_bgm_track.get("title") or "BGM") if bgm_url else ""
    shots = _flatten_shots(scene_groups)
    mg_clip_by_shot = _mg_clip_by_shot_from_project(project, shots)
    durations = [_positive_float(shot.get("duration_seconds"), 6.0) for shot in shots]
    total_duration = sum(durations)
    scene_markup = []
    nav_markup = []

    for index, shot in enumerate(shots, start=1):
        shot_id = str(shot.get("id") or "")
        narration = str(scripts.get(shot_id) or shot.get("narration") or "")
        option = _selected_broll_option_for_preview(shot, selected_broll)
        asset_url = str(option.get("asset_url") or "")
        info = shot.get("information_layer") if isinstance(shot.get("information_layer"), dict) else {}
        title = str(shot.get("title") or f"分镜 {index}")
        media_markup = _player_media_markup(asset_url, str(option.get("title") or title))
        voice_asset = voice_assets.get(shot_id) if isinstance(voice_assets.get(shot_id), dict) else {}
        voice_url = str(voice_asset.get("asset_url") or voice_asset.get("url") or "")
        voice_markup = (
            f'<audio class="voice-audio" data-shot-id="{html.escape(shot_id, quote=True)}" '
            f'src="{html.escape(voice_url, quote=True)}" preload="auto"></audio>'
            if voice_url
            else ""
        )
        fallback_markup = ""
        if not media_markup:
            fallback_markup = f"""
              <div class="media-empty">
                <span>未下载真实素材</span>
                <strong>{html.escape(str(option.get("title") or title))}</strong>
                <p>{html.escape(str(option.get("description") or shot.get("broll_prompt") or ""))}</p>
              </div>
            """

        html_enabled = _shot_uses_html(shot)
        html_overlay = ""
        if html_enabled:
            html_design = _html_design_for_preview(shot, html_design_overrides)
            mg_clip = mg_clip_by_shot.get(shot_id) or _mg_clip_for_preview(shot, html_design)
            html_layer_markup = _html_layer_markup_for_preview(shot, info, html_design, mg_clip)
            contract_version = _html_layer_contract_version(mg_clip)
            html_overlay = f"""
              <div class="info-layer drawn-html-layer mg-clip-layer" data-render-mode="drawn_html_overlay" data-contract="{html.escape(contract_version, quote=True)}" data-parent-contract="mg_clip_v1" data-mg-clip-id="{html.escape(str(mg_clip.get("id") or ""), quote=True)}" data-bound-shots="{html.escape(','.join(str(item) for item in mg_clip.get("bound_shots", [])), quote=True)}" data-template="{html.escape(str(mg_clip.get("mg_template") or ""), quote=True)}">
                {html_layer_markup}
              </div>
            """

        scene_markup.append(
            f"""
            <section class="scene{' scene--html' if html_enabled else ''}" data-index="{index}">
              <div class="media">{media_markup}{fallback_markup}</div>
              {voice_markup}
              <div class="grade"></div>
              {html_overlay}
              {f'<div class="avatar">人</div>' if avatar_enabled else ''}
              <div class="caption">{html.escape(narration)}</div>
            </section>
            """
        )
        nav_markup.append(
            f'<button type="button" class="thumb{" active" if index == 1 else ""}" data-target="{index}">'
            f'<span>{index:02d}</span><strong>{html.escape(title)}</strong></button>'
        )

    return f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>{html.escape(topic)} - {html.escape(page_label)}</title>
  <style>
    * {{ box-sizing: border-box; }}
    body {{ margin: 0; min-height: 100vh; overflow: hidden; background: #030712; color: #f8fafc; font-family: "Noto Sans CJK SC", Inter, sans-serif; }}
    .shell {{ height: 100vh; display: grid; grid-template-rows: auto minmax(0,1fr) auto; }}
    header {{ display: flex; align-items: center; justify-content: space-between; gap: 20px; padding: 14px 20px; border-bottom: 1px solid rgba(148,163,184,.18); background: rgba(3,7,18,.92); }}
    h1 {{ margin: 0; font-size: 17px; line-height: 1.2; }} .meta {{ color: #94a3b8; font-size: 12px; font-weight: 800; text-align: right; }}
    .stage {{ min-height: 0; display: grid; place-items: center; padding: 18px; }}
    .player {{ position: relative; width: min(100%, calc((100vh - 178px) * 16 / 9)); max-width: 1440px; aspect-ratio: 16 / 9; overflow: hidden; border-radius: 12px; background: #0f172a; box-shadow: 0 24px 90px rgba(0,0,0,.48); border: 1px solid rgba(148,163,184,.2); }}
    .scene {{ position: absolute; inset: 0; opacity: 0; pointer-events: none; transition: opacity .35s ease; }}
    .scene.active {{ opacity: 1; pointer-events: auto; }}
    .media, .media img, .media video, .media-empty {{ position: absolute; inset: 0; width: 100%; height: 100%; object-fit: cover; }}
    .media-empty {{ display: flex; flex-direction: column; justify-content: center; align-items: flex-start; gap: 10px; padding: 8%; background: radial-gradient(circle at 48% 34%, rgba(255,255,255,.18), transparent 18%), linear-gradient(135deg,#0f172a,#1e293b 48%,#164e63); }}
    .media-empty span {{ padding: 6px 9px; border-radius: 6px; background: rgba(250,204,21,.18); color: #fde68a; font-size: 12px; font-weight: 900; }} .media-empty strong {{ max-width: 56%; font-size: 34px; line-height: 1.12; }} .media-empty p {{ max-width: 48%; margin: 0; color: #cbd5e1; line-height: 1.6; }}
    .scene--html .media-empty {{ opacity: .32; filter: saturate(.82); }}
    .scene--html .media-empty span, .scene--html .media-empty strong, .scene--html .media-empty p {{ opacity: .28; }}
    .grade {{ position: absolute; inset: 0; background: linear-gradient(180deg, rgba(0,0,0,.04), rgba(0,0,0,.54)); }}
    .info-layer {{ position: absolute; inset: 0; text-align: left; pointer-events: none; animation: layerIn .7s ease both; }}
    .custom-html-frame {{ width: 100%; height: 100%; border: 0; display: block; background: transparent; }}
    {_mg_visual_system_css()}
    .player .mg-system, .player .mg-stage {{ background: transparent !important; box-shadow: none !important; border-color: rgba(255,255,255,.16) !important; }}
    .player .mg-system__texture, .player .mg-texture {{ opacity: .14 !important; }}
    .player .mg-system__header b, .player header b {{ background: rgba(250,204,21,.86) !important; }}
    .player .mg-block, .player .mg-causal-node, .player .mg-timeline-step, .player .mg-compare-lane, .player .mg-quadrant-cell, .player .mg-cost-lane, .player .mg-strategy-panel, .player .mg-flow-node, .player .mg-director-timeline li {{ background: rgba(2,6,23,.36) !important; backdrop-filter: blur(10px); }}
    .player .mg-director-summary, .player .mg-system__result {{ background: rgba(250,204,21,.84) !important; }}
    .caption {{ position: absolute; left: 30px; right: 132px; bottom: 28px; padding: 12px 16px; border-radius: 8px; background: rgba(0,0,0,.58); font-size: clamp(14px, 1.3vw, 20px); line-height: 1.45; font-weight: 900; backdrop-filter: blur(8px); }}
    .avatar {{ position: absolute; right: 30px; bottom: 28px; width: 82px; height: 82px; display: grid; place-items: center; border-radius: 18px; background: rgba(255,255,255,.16); border: 1px solid rgba(255,255,255,.28); font-size: 24px; font-weight: 950; backdrop-filter: blur(10px); }}
    .controls {{ position: absolute; right: 24px; top: 24px; display: flex; gap: 12px; z-index: 40; }}
    .control {{ width: 46px; height: 46px; border: 0; border-radius: 999px; background: rgba(255,255,255,.92); color: #020617; font-size: 20px; font-weight: 950; cursor: pointer; box-shadow: 0 12px 28px rgba(0,0,0,.28); }}
    .player.playing .controls {{ opacity: .22; transition: opacity .2s ease; }} .player.playing:hover .controls {{ opacity: 1; }}
    footer {{ display: grid; gap: 10px; padding: 12px 20px 16px; border-top: 1px solid rgba(148,163,184,.18); background: rgba(3,7,18,.96); }}
    .timeline {{ height: 7px; border-radius: 999px; background: rgba(148,163,184,.2); overflow: hidden; }} .bar {{ height: 100%; width: 0%; background: #67e8f9; transition: width .2s linear; }}
    .thumbs {{ display: flex; gap: 9px; overflow-x: auto; padding-bottom: 3px; }}
    .thumb {{ min-width: 160px; border: 1px solid rgba(148,163,184,.22); border-radius: 9px; padding: 9px; background: rgba(15,23,42,.72); color: #cbd5e1; text-align: left; cursor: pointer; }}
    .thumb.active {{ border-color: #67e8f9; color: white; background: rgba(8,47,73,.74); }} .thumb span {{ display: block; color: #67e8f9; font-weight: 950; }} .thumb strong {{ display: block; margin-top: 4px; font-size: 12px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }}
    @keyframes layerIn {{ from {{ opacity: 0; transform: translateY(18px); }} to {{ opacity: 1; transform: translateY(0); }} }}
    @media (max-width: 760px) {{ body {{ overflow: auto; }} .shell {{ min-height: 100vh; height: auto; }} header {{ align-items: flex-start; flex-direction: column; }} .stage {{ padding: 10px; }} .player {{ width: 100%; }} .caption {{ right: 30px; font-size: 14px; }} .avatar {{ display: none; }} }}
  </style>
</head>
<body>
  <div class="shell">
    <header>
      <div><h1>{html.escape(topic)}</h1></div>
      <div class="meta">{html.escape(page_label)} · {len(shots)} 个分镜 · {round(total_duration)}s · BGM {'开' if bgm_enabled else '关'}</div>
    </header>
    <main class="stage">
      <div class="player" id="player">
        {''.join(scene_markup)}
        <div class="controls"><button class="control" id="play" type="button">▶</button></div>
      </div>
      {f'<audio class="bgm-audio" data-role="bgm-a" src="{html.escape(bgm_url, quote=True)}" preload="auto" crossorigin="anonymous"></audio><audio class="bgm-audio" data-role="bgm-b" src="{html.escape(bgm_url, quote=True)}" preload="auto" crossorigin="anonymous"></audio>' if bgm_url else ''}
    </main>
    <footer>
      <div class="timeline"><div class="bar" id="bar"></div></div>
      <div class="thumbs">{''.join(nav_markup)}</div>
    </footer>
  </div>
  <script>
    const player = document.getElementById('player');
    const scenes = Array.from(document.querySelectorAll('.scene'));
    const thumbs = Array.from(document.querySelectorAll('.thumb'));
    const play = document.getElementById('play');
    const bar = document.getElementById('bar');
    const durations = {json.dumps(durations)};
    const bgmEnabled = {json.dumps(bool(bgm_url))};
    const bgmLabel = {json.dumps(bgm_title, ensure_ascii=False)};
    const bgmTargetVolume = {json.dumps(round(bgm_volume, 3))};
    const bgmA = document.querySelector('[data-role="bgm-a"]');
    const bgmB = document.querySelector('[data-role="bgm-b"]');
    const bgmCrossfadeSeconds = 2;
    const bgmFadeIntervalMs = 80;
    let current = 0;
    let playing = false;
    let progress = 0;
    let activeBgm = bgmA;
    let standbyBgm = bgmB;
    let bgmCrossfadeTimer = null;
    let bgmMonitorTimer = null;
    function activeVideo() {{ return scenes[current]?.querySelector('video'); }}
    function activeVoice() {{ return scenes[current]?.querySelector('audio.voice-audio'); }}
    function syncVideos() {{
      scenes.forEach((scene, index) => {{
        const video = scene.querySelector('video');
        const voice = scene.querySelector('audio.voice-audio');
        if (video && (index !== current || !playing)) video.pause();
        if (voice && (index !== current || !playing)) {{
          voice.pause();
          voice.currentTime = 0;
        }}
      }});
      const video = activeVideo();
      if (video && playing) video.play().catch(() => {{}});
      const voice = activeVoice();
      if (voice && playing) voice.play().catch(() => {{}});
    }}
    function clearBgmTimers() {{
      if (bgmCrossfadeTimer) window.clearInterval(bgmCrossfadeTimer);
      if (bgmMonitorTimer) window.clearInterval(bgmMonitorTimer);
      bgmCrossfadeTimer = null;
      bgmMonitorTimer = null;
    }}
    function fadeAudio(audio, from, to, seconds, onDone) {{
      if (!audio) return;
      const steps = Math.max(1, Math.round(seconds * 1000 / bgmFadeIntervalMs));
      let step = 0;
      const delta = (to - from) / steps;
      audio.volume = Math.max(0, Math.min(1, from));
      const timer = window.setInterval(() => {{
        step += 1;
        audio.volume = Math.max(0, Math.min(1, from + delta * step));
        if (step >= steps) {{
          window.clearInterval(timer);
          audio.volume = Math.max(0, Math.min(1, to));
          if (onDone) onDone();
        }}
      }}, bgmFadeIntervalMs);
    }}
    function crossfadeBgmLoop() {{
      if (!bgmEnabled || !playing || !activeBgm || !standbyBgm) return;
      standbyBgm.currentTime = 0;
      standbyBgm.volume = 0;
      standbyBgm.play().catch(() => {{}});
      fadeAudio(activeBgm, activeBgm.volume || bgmTargetVolume, 0, bgmCrossfadeSeconds, () => {{
        activeBgm.pause();
        activeBgm.currentTime = 0;
      }});
      fadeAudio(standbyBgm, 0, bgmTargetVolume, bgmCrossfadeSeconds);
      const previous = activeBgm;
      activeBgm = standbyBgm;
      standbyBgm = previous;
    }}
    function startBgm() {{
      if (!bgmEnabled || !activeBgm || !standbyBgm) return;
      clearBgmTimers();
      activeBgm.volume = 0;
      activeBgm.currentTime = 0;
      standbyBgm.pause();
      standbyBgm.currentTime = 0;
      activeBgm.play().catch(() => {{}});
      fadeAudio(activeBgm, 0, bgmTargetVolume, 1.2);
      bgmMonitorTimer = window.setInterval(() => {{
        if (!playing || !activeBgm.duration || Number.isNaN(activeBgm.duration)) return;
        if (activeBgm.duration - activeBgm.currentTime <= bgmCrossfadeSeconds + 0.15) {{
          crossfadeBgmLoop();
        }}
      }}, 200);
    }}
    function stopBgm() {{
      if (!bgmEnabled) return;
      clearBgmTimers();
      [bgmA, bgmB].forEach((audio) => {{
        if (!audio) return;
        audio.pause();
        audio.currentTime = 0;
        audio.volume = 0;
      }});
      activeBgm = bgmA;
      standbyBgm = bgmB;
    }}
    function show(index) {{
      current = Math.max(0, Math.min(index, scenes.length - 1));
      progress = 0;
      scenes.forEach((scene, i) => scene.classList.toggle('active', i === current));
      thumbs.forEach((thumb, i) => thumb.classList.toggle('active', i === current));
      bar.style.width = '0%';
      const video = activeVideo();
      if (video) video.currentTime = 0;
      syncVideos();
    }}
    function setPlaying(next) {{
      playing = next;
      play.textContent = playing ? 'Ⅱ' : '▶';
      player.classList.toggle('playing', playing);
      syncVideos();
      if (playing) startBgm(); else stopBgm();
    }}
    thumbs.forEach((thumb, i) => thumb.addEventListener('click', () => show(i)));
    play.addEventListener('click', () => setPlaying(!playing));
    player.addEventListener('click', (event) => {{
      if (event.target === play || event.target.closest('.thumb')) return;
      setPlaying(!playing);
    }});
    show(0);
    setInterval(() => {{
      if (!playing || !scenes.length) return;
      const duration = Math.max(1, durations[current] || 6);
      progress += 0.2;
      bar.style.width = Math.min(100, progress / duration * 100) + '%';
      if (progress >= duration) show((current + 1) % scenes.length);
    }}, 200);
  </script>
</body>
</html>"""


def build_composition_preview_html(project: Dict[str, Any]) -> str:
    return _build_video_studio_player_html(project, page_label="合成预览")


def build_final_video_html(project: Dict[str, Any]) -> str:
    return _build_video_studio_player_html(project, page_label="最终作品")


def _selected_broll_option_for_preview(shot: Dict[str, Any], selected_broll: Dict[str, Any]) -> Dict[str, Any]:
    options = shot.get("broll_options") if isinstance(shot.get("broll_options"), list) else []
    selected_id = str(selected_broll.get(str(shot.get("id") or "")) or "")
    for option in options:
        if isinstance(option, dict) and str(option.get("id") or "") == selected_id:
            return option
    return next((option for option in options if isinstance(option, dict)), {})


def _html_design_for_preview(shot: Dict[str, Any], html_design_overrides: Dict[str, Any]) -> Dict[str, Any]:
    base = shot.get("html_design") if isinstance(shot.get("html_design"), dict) else {}
    override = html_design_overrides.get(str(shot.get("id") or ""))
    if not isinstance(override, dict):
        return base
    scene_spec = override.get("scene_design_spec") if isinstance(override.get("scene_design_spec"), dict) else {}
    return {
        **base,
        **scene_spec,
        "illustration_plan": scene_spec.get("illustration_plan") if isinstance(scene_spec.get("illustration_plan"), dict) else base.get("illustration_plan"),
        "motion_sequence": scene_spec.get("motion_sequence") if isinstance(scene_spec.get("motion_sequence"), list) else base.get("motion_sequence"),
        "content_slots": scene_spec.get("content_slots") if isinstance(scene_spec.get("content_slots"), list) else base.get("content_slots"),
    }


def _html_layer_contract_version(mg_clip: Dict[str, Any]) -> str:
    design_doc = mg_clip.get("design_doc") if isinstance(mg_clip.get("design_doc"), dict) else {}
    if design_doc.get("version") == "mg_design_doc_v1":
        return "mg_design_doc_v1"
    return "mg_clip_v1"


def _html_layer_markup_for_preview(
    shot: Dict[str, Any],
    info: Dict[str, Any],
    html_design: Dict[str, Any],
    mg_clip: Dict[str, Any],
) -> str:
    custom_markup = _custom_html_iframe_markup(html_design)
    if custom_markup:
        return custom_markup
    render_strategy = str(mg_clip.get("render_strategy") or shot.get("html_render_strategy") or html_design.get("render_strategy") or "llm_bespoke_html")
    if render_strategy == "template":
        return _mg_template_system_markup(shot, info, html_design, mg_clip)
    design_doc = mg_clip.get("design_doc") if isinstance(mg_clip.get("design_doc"), dict) else {}
    if design_doc.get("version") == "mg_design_doc_v1":
        return _mg_design_doc_markup(design_doc, shot, info, html_design, mg_clip)
    return _mg_visual_system_markup(shot, info, html_design, mg_clip)


def _custom_html_iframe_markup(html_design: Dict[str, Any]) -> str:
    custom_html = _activate_bespoke_html_layers(str(html_design.get("custom_html") or "").strip())
    custom_css = str(html_design.get("custom_css") or "").strip()
    if not custom_html and not custom_css:
        return ""
    srcdoc = f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <style>
    html, body {{ margin: 0; width: 100%; height: 100%; overflow: hidden; background: transparent !important; }}
    body {{ color: #f8fafc; font-family: "Noto Sans CJK SC", Inter, sans-serif; }}
    .ai-mg-layer {{ background: transparent !important; }}
    {custom_css}
    html, body {{ background: transparent !important; }}
    .ai-mg-layer {{ background: transparent !important; }}
  </style>
</head>
<body>{custom_html}</body>
</html>"""
    return (
        '<iframe class="custom-html-frame" '
        'sandbox="" '
        'title="用户微调 HTML 信息层" '
        f'srcdoc="{html.escape(srcdoc, quote=True)}"></iframe>'
    )


def _mg_clip_for_preview(shot: Dict[str, Any], html_design: Dict[str, Any]) -> Dict[str, Any]:
    patched_shot = dict(shot)
    patched_shot["html_design"] = html_design
    return _mg_clip_for_shot(patched_shot)


def _normalize_mg_visual_system(value: Any) -> str:
    raw = str(value or "").strip().lower().replace("_", "-")
    aliases = {
        "metric": "metric",
        "metrics": "metric",
        "metric-callout": "metric",
        "center-diagram": "metric",
        "scoreboard": "metric",
        "chart": "metric",
        "data": "metric",
        "causal": "causal",
        "cause": "causal",
        "causal-chain": "causal",
        "chain": "causal",
        "process": "causal",
        "route": "route",
        "route-trace": "route",
        "map": "route",
        "path": "route",
        "timeline": "timeline",
        "time-line": "timeline",
        "stage-rail": "timeline",
        "comparison": "comparison",
        "compare": "comparison",
        "before-after": "comparison",
        "reveal": "reveal",
        "scan": "reveal",
        "scanner": "reveal",
        "spotlight": "reveal",
        "mask": "reveal",
        "satellite-reveal": "reveal",
        "dashboard": "comparison",
        "split-focus": "comparison",
        "radial-map": "comparison",
        "field-labels": "comparison",
        "keyword-stamp": "comparison",
    }
    return aliases.get(raw, raw if raw in VALID_MG_VISUAL_SYSTEMS else "")


def _mg_visual_system_from_text(text: str) -> str:
    raw = str(text or "")
    direct = _normalize_mg_visual_system(raw)
    if direct:
        return direct
    if "metric_callout" in raw or re.search(r"\d+(?:\.\d+)?\s*(?:%|％|万|亿|元|美元|年|点|倍|人|家|次)", raw):
        return "metric"
    if "causal_chain" in raw or any(token in raw for token in ("因为", "导致", "形成", "所以", "机制", "原因", "循环", "链", "传导")):
        return "causal"
    if "route_trace" in raw or any(token in raw for token in ("路线", "路径", "迁移", "流向", "地图", "城市", "地区", "国家", "从", "到")):
        return "route"
    if any(token in raw for token in ("时间线", "时间轴", "阶段", "首先", "随后", "最后", "年代", "周期")) or re.search(r"(?:19|20)\d{2}", raw):
        return "timeline"
    if any(token in raw for token in ("扫描", "揭示", "遮罩", "探照", "露出", "卫星纹理", "证据浮现")):
        return "reveal"
    if any(token in raw for token in ("对比", "相比", "差异", "两端", "一边", "另一边", "前后", "vs", "VS")):
        return "comparison"
    return ""


def _mg_visual_system_kind(
    shot: Dict[str, Any],
    info: Dict[str, Any],
    html_design: Dict[str, Any],
    mg_clip: Dict[str, Any] | None,
) -> str:
    illustration = html_design.get("illustration_plan") if isinstance(html_design.get("illustration_plan"), dict) else {}
    mg_director = shot.get("mg_director") if isinstance(shot.get("mg_director"), dict) else {}
    clip_director = (mg_clip or {}).get("mg_director") if isinstance(mg_clip, dict) and isinstance((mg_clip or {}).get("mg_director"), dict) else {}
    candidates = [
        clip_director.get("visual_system"),
        mg_director.get("visual_system"),
        (mg_clip or {}).get("visual_system") if isinstance(mg_clip, dict) else "",
        html_design.get("visual_system"),
        illustration.get("visual_system"),
        info.get("overlay_type"),
    ]
    for candidate in candidates:
        normalized = _normalize_mg_visual_system(candidate)
        if normalized:
            return normalized
    overlay_type = str(info.get("overlay_type") or "")
    overlay_map = {
        "metric_callout": "metric",
        "causal_chain": "causal",
        "route_trace": "route",
        "keyword_stamp": "comparison",
        "field_labels": "comparison",
    }
    if overlay_type in overlay_map:
        return overlay_map[overlay_type]
    inferred = _mg_visual_system_from_text(
        " ".join([
            str(shot.get("title") or ""),
            str(shot.get("narration") or ""),
            str(info.get("keyword") or ""),
            str(info.get("primary_fact") or ""),
            str(info.get("takeaway") or ""),
            str(mg_director.get("story_goal") or ""),
            str(mg_director.get("main_visual_metaphor") or ""),
            str(mg_director.get("html_brief") or ""),
        ])
    )
    return inferred or "comparison"


