def _player_media_markup(asset_url: str, title: str) -> str:
    if not asset_url:
        return ""
    escaped_url = html.escape(asset_url, quote=True)
    escaped_title = html.escape(title or "B-roll")
    if re.search(r"\.(mp4|webm|mov)(?:\?|$)", asset_url, flags=re.IGNORECASE):
        return f'<video src="{escaped_url}" muted loop playsinline preload="metadata"></video>'
    return f'<img src="{escaped_url}" alt="{escaped_title}" />'


def _scene_role_for_shot(raw_shot: Dict[str, Any], production_format: str, shot_counter: int) -> str:
    if production_format == "broll":
        return FULL_BROLL
    raw = str(raw_shot.get("scene_role") or "").strip()
    if raw in VALID_SCENE_ROLES:
        return raw
    raw_visual = str(raw_shot.get("visual_role") or "").strip()
    if raw_visual == "avatar_primary":
        return AVATAR_ONLY
    if raw_visual == "broll_primary":
        return FULL_BROLL
    return FULL_BROLL


def _visual_role_for_scene_role(scene_role: str) -> str:
    if scene_role == AVATAR_ONLY:
        return "avatar_primary"
    return "broll_primary" if scene_role == FULL_BROLL else "hybrid_broll_html"


def _is_avatar_only_voiceover_unit(
    scene: Dict[str, Any],
    unit: Dict[str, Any],
    unit_index: int,
    unit_count: int,
    production_format: str,
) -> bool:
    if production_format != "broll_html":
        return False
    raw_role = str(unit.get("scene_role") or unit.get("visual_mode") or scene.get("scene_role") or scene.get("visual_mode") or "").strip()
    raw_visual = str(unit.get("visual_role") or scene.get("visual_role") or "").strip()
    if raw_role == AVATAR_ONLY or raw_visual == "avatar_primary":
        return True
    text = " ".join(
        str(value or "")
        for value in [
            unit.get("title"),
            unit.get("text"),
            scene.get("title"),
            scene.get("scene_type"),
            scene.get("director_note"),
        ]
    )
    if re.search(r"(纯数字人|数字人口播|讲解员出镜|主持人口播|口播观点|观点开场|总结判断|结尾判断)", text):
        return True
    if unit_count >= 3 and unit_index == 1 and re.search(r"(先说结论|先给结论|口播开场|观点开场|讲解员开场|主持人开场)", text):
        return True
    if unit_count >= 3 and unit_index == unit_count and re.search(r"(数字人总结|口播总结|总结判断|结尾判断|主持人收束|讲解员收束)", text):
        return True
    return False


def _information_layer_for_shot(
    raw_shot: Dict[str, Any],
    shot_id: str,
    narration: str,
    prompt: str,
    scene_role: str,
) -> Dict[str, Any]:
    raw = raw_shot.get("information_layer") if isinstance(raw_shot.get("information_layer"), dict) else {}
    mg_director = raw_shot.get("mg_director") if isinstance(raw_shot.get("mg_director"), dict) else {}
    if not raw and _mg_director_enabled(mg_director):
        return {
            **_information_layer_from_mg_director(raw_shot, mg_director, narration),
            "version": "information_layer_v1",
            "scene_id": shot_id,
            "enabled": scene_role == BROLL_BACKDROP,
            "shape": _shape_for_overlay_type(
                _information_layer_from_mg_director(raw_shot, mg_director, narration).get("overlay_type", "field_labels")
            ),
            "text_budget": {
                "max_blocks": 3,
                "max_total_chars": 90,
                "max_label_chars": 12,
            },
        }
    title = str(raw_shot.get("title") or "").strip()
    keyword = _prompt_text(raw.get("keyword") or title or narration or prompt)
    overlay_type = str(raw.get("overlay_type") or "").strip()
    if overlay_type not in VALID_OVERLAY_TYPES:
        overlay_type = _overlay_type_from_text(" ".join([title, narration, prompt]))
    items = raw.get("items") if isinstance(raw.get("items"), list) else []
    normalized_items = []
    for index, item in enumerate(items[:4], start=1):
        if not isinstance(item, dict):
            continue
        text = _prompt_text(item.get("text") or item.get("label") or "")
        if text:
            normalized_items.append({"label": _prompt_text(item.get("label") or f"{index:02d}"), "text": text})
    if not normalized_items:
        normalized_items = [
            {"label": f"{index:02d}", "text": _prompt_text(part)}
            for index, part in enumerate(_clauses(narration or prompt, 3), start=1)
            if _prompt_text(part)
        ]
    return {
        "version": "information_layer_v1",
        "scene_id": shot_id,
        "enabled": scene_role == BROLL_BACKDROP,
        "overlay_type": overlay_type,
        "shape": _shape_for_overlay_type(overlay_type),
        "keyword": keyword or "关键信息",
        "primary_fact": _prompt_text(raw.get("primary_fact") or title or narration),
        "takeaway": _prompt_text(raw.get("takeaway") or narration or prompt),
        "items": normalized_items[:4],
        "density": str(raw.get("density") or ("medium" if len(normalized_items) >= 3 else "light")),
        "text_budget": {
            "max_blocks": 4 if len(normalized_items) >= 3 else 2,
            "max_total_chars": 120 if len(normalized_items) >= 3 else 64,
            "max_label_chars": 12,
        },
    }


def _overlay_type_from_text(text: str) -> str:
    if re.search(r"\d+(?:\.\d+)?\s*(?:%|％|万|亿|元|美元|年|点|倍)", text):
        return "metric_callout"
    if any(token in text for token in ("因为", "导致", "形成", "所以", "机制", "原因", "循环", "链")):
        return "causal_chain"
    if any(token in text for token in ("路线", "路径", "城市", "地区", "国家", "东京", "日本", "上海")):
        return "route_trace"
    return "field_labels"


def _shape_for_overlay_type(overlay_type: str) -> str:
    if overlay_type == "metric_callout":
        return "metric_takeaway"
    if overlay_type == "route_trace":
        return "route_nodes"
    if overlay_type == "causal_chain":
        return "causal_chain"
    return "keyword_pins"


def _clauses(text: str, limit: int) -> List[str]:
    protected = re.sub(r"(?<=\d),(?=\d)", "§COMMA§", str(text or ""))
    return [
        part.replace("§COMMA§", ",").strip(" ，。；、:：")
        for part in re.split(r"[。；;！？!?，,\n]+", protected)
        if part.strip(" ，。；、:：")
    ][:limit]


def _short_text(value: Any, limit: int) -> str:
    text = re.sub(r"\s+", " ", str(value or "")).strip()
    if len(text) > limit:
        return text[: max(1, limit - 1)] + "…"
    return text


def _prompt_text(value: Any) -> str:
    return re.sub(r"\s+", " ", str(value or "")).strip()


def _screen_text_key(value: Any) -> str:
    text = str(value or "").lower()
    text = re.sub(r"(\d{4})年(\d{1,2})月(\d{1,2})日", r"\1\2\3", text)
    return re.sub(r"[\W_]+", "", text, flags=re.UNICODE)


def _screen_text_seen(value: Any, seen_values: List[str]) -> bool:
    key = _screen_text_key(value)
    if not key:
        return True
    current_metrics = _screen_text_metric_keys(value)
    for seen in seen_values:
        seen_key = _screen_text_key(seen)
        if key == seen:
            return True
        if key == seen_key:
            return True
        if len(key) >= 6 and len(seen_key) >= 6 and (key in seen_key or seen_key in key):
            return True
        if current_metrics and current_metrics.intersection(_screen_text_metric_keys(seen)):
            return True
    return False


def _screen_text_metric_keys(value: Any) -> set[str]:
    text = str(value or "")
    return {
        match.group(0).replace("％", "%")
        for match in re.finditer(r"\d+(?:\.\d+)?\s*(?:%|％|万亿|万|亿|元|美元|日元|倍|人|家|次|点)", text)
    }


def _screen_text_metric_score(value: str) -> int:
    text = str(value or "")
    score = 0
    if re.search(r"%|％", text):
        score += 80
    if re.search(r"万亿|万|亿|元|美元|日元|倍|人|家|次|点", text):
        score += 56
    if re.search(r"\d", text):
        score += 24
    if re.fullmatch(r".{0,4}\d{3,4}年.{0,4}", text):
        score -= 32
    score += min(18, len(text))
    return score


def _screen_text_phrase(value: Any, *, limit: int, seen_keys: List[str] | None = None) -> str:
    text = _prompt_text(value)
    if not text:
        return ""
    seen_keys = seen_keys or []
    clauses = _clauses(text, 8) or [text]
    digit_clauses = sorted(
        [clause for clause in clauses if re.search(r"\d|%|％", clause)],
        key=_screen_text_metric_score,
        reverse=True,
    )
    conclusion_clauses = [
        clause
        for clause in clauses
        if any(token in clause for token in ("锁住", "锁定", "抗风险", "下降", "导致", "变成", "不是", "而是", "压力", "后果"))
    ]
    candidates = [*digit_clauses, *conclusion_clauses, *clauses, text]
    for candidate in candidates:
        phrase = _prompt_text(candidate).strip(" ，。；、:：")
        if not phrase:
            continue
        if _screen_text_seen(phrase, seen_keys):
            continue
        return phrase[:limit]
    return _prompt_text(candidates[0])[:limit] if candidates else ""


def _documentary_overlay_mode(value: Any, context: str = "") -> str:
    raw = str(value or "").strip().lower()
    if raw in {"documentary", "explainer"}:
        return raw
    evidence_tokens = (
        "历史",
        "殖民",
        "地理",
        "生态",
        "卫星",
        "调查",
        "证据",
        "地图",
        "河流",
        "国家",
        "战争",
        "档案",
        "路线",
        "植被",
        "土地",
    )
    return "documentary" if any(token in str(context or "") for token in evidence_tokens) else "explainer"


def _normalize_topic_blocks(value: Any, topic: str) -> List[Dict[str, str]]:
    if isinstance(value, list):
        blocks = []
        for index, item in enumerate(value[:6], start=1):
            if isinstance(item, dict):
                blocks.append({
                    "title": str(item.get("title") or f"主题板块 {index}"),
                    "description": str(item.get("description") or ""),
                    "production_value": str(item.get("production_value") or ""),
                })
        if blocks:
            return blocks
    keywords = _topic_keywords(topic)
    return [
        {
            "title": keyword,
            "description": f"围绕“{keyword}”展开一个可视化段落。",
            "production_value": "可转化为 B-roll 检索词和 HTML 信息层。",
        }
        for keyword in (keywords[:3] or [topic])
    ]


def _normalize_key_data_scenes(value: Any, topic: str) -> List[Dict[str, str]]:
    if isinstance(value, list):
        scenes = []
        for index, item in enumerate(value[:8], start=1):
            if isinstance(item, dict):
                scenes.append({
                    "label": str(item.get("label") or f"关键场景 {index}"),
                    "value": str(item.get("value") or "待核验"),
                    "scene_hint": str(item.get("scene_hint") or "可做成信息块或素材检索线索"),
                })
        if scenes:
            return scenes
    return [
        {
            "label": "主题关键词",
            "value": topic,
            "scene_hint": "先作为素材检索和信息层标题，事实数据后续核验。",
        }
    ]


def _normalize_voiceover_units(value: Any, fallback: Any = None) -> List[Dict[str, Any]]:
    units: List[Dict[str, Any]] = []
    if isinstance(value, list):
        for index, item in enumerate(value[:4], start=1):
            if isinstance(item, dict):
                text = str(item.get("text") or item.get("narration") or item.get("script") or "").strip()
                if text:
                    units.append({
                        "id": str(item.get("id") or f"script-{index:02d}"),
                        "text": text,
                        "duration_seconds": _positive_int(item.get("duration_seconds"), 7),
                    })
            elif str(item).strip():
                units.append({"id": f"script-{index:02d}", "text": str(item).strip(), "duration_seconds": 7})
    if not units and str(fallback or "").strip():
        clauses = _clauses(str(fallback), 3) or [str(fallback).strip()]
        units = [
            {"id": f"script-{index:02d}", "text": clause, "duration_seconds": 7}
            for index, clause in enumerate(clauses[:3], start=1)
        ]
    return units


def _normalize_asset_search_plan(
    value: Any,
    topic: str,
    raw_scene: Dict[str, Any],
    voice_units: List[Dict[str, Any]],
) -> Dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    joined_voice = " ".join(str(unit.get("text") or "") for unit in voice_units)
    summary = str(raw.get("summary") or raw_scene.get("visual_description") or raw_scene.get("description") or joined_voice or topic)
    queries = _broll_search_queries(
        raw.get("search_queries"),
        fallback=[raw_scene.get("title"), summary, *(_topic_keywords(topic)[:3])],
    )
    return {
        "summary": summary,
        "search_queries": queries[:6],
        "material_types": _string_list(raw.get("material_types"), [f"{topic}相关真实素材", "资料画面", "人物/空间镜头"]),
        "named_entities": _string_list(raw.get("named_entities"), _topic_keywords(topic)[:5]),
        "duration_seconds": _positive_int(raw.get("duration_seconds"), max(6, sum(_positive_int(unit.get("duration_seconds"), 7) for unit in voice_units))),
    }


def _normalize_mg_director(
    value: Any,
    raw_scene: Dict[str, Any],
    production_format: str,
    voice_units: List[Dict[str, Any]],
) -> Dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    enabled = production_format == "broll_html" and bool(raw.get("enabled", False))
    render_strategy = str(raw.get("render_strategy") or ("llm_bespoke_html" if enabled else "none"))
    if render_strategy not in {"llm_bespoke_html", "template", "none"}:
        render_strategy = "llm_bespoke_html" if enabled else "none"
    scope = str(raw.get("scope") or ("cross_shot" if len(voice_units) > 1 else "single_shot"))
    if scope not in {"single_shot", "cross_shot"}:
        scope = "single_shot"
    voice_ids = [str(unit.get("id") or "") for unit in voice_units if isinstance(unit, dict) and str(unit.get("id") or "").strip()]
    bound_voice_ids = _string_list(raw.get("bound_voiceover_unit_ids"), voice_ids if enabled else [])
    visual_system = _normalize_mg_visual_system(raw.get("visual_system") or "")
    visual_fx = _normalize_mg_visual_fx(
        raw.get("visual_fx"),
        visual_system,
        " ".join(
            [
                str(raw.get("main_visual_metaphor") or ""),
                str(raw.get("html_brief") or ""),
                str(raw_scene.get("title") or ""),
                str(raw_scene.get("intent") or raw_scene.get("director_note") or ""),
            ]
        ),
    )
    composition = _normalize_mg_composition(
        raw.get("composition"),
        visual_system,
        semantic_text=" ".join(
            [
                str(raw_scene.get("title") or ""),
                str(raw.get("main_visual_metaphor") or ""),
                str(raw.get("one_learning_point") or ""),
            ]
        ),
    )
    logic_chain = []
    for index, item in enumerate(raw.get("logic_chain") if isinstance(raw.get("logic_chain"), list) else [], start=1):
        if not isinstance(item, dict):
            continue
        text = _prompt_text(item.get("text") or item.get("label") or "")
        if not text:
            continue
        logic_chain.append(
            {
                "label": _screen_text_phrase(item.get("label") or f"{index:02d}", limit=14),
                "text": _short_text(text, 56),
                "role": _short_text(item.get("role") or "", 20),
            }
        )
        if len(logic_chain) >= 5:
            break
    screen_slots = []
    seen: List[str] = []
    for item in (raw.get("screen_slots") if isinstance(raw.get("screen_slots"), list) else []):
        if not isinstance(item, dict):
            continue
        text = _screen_text_phrase(item.get("text") or "", limit=28, seen_keys=seen)
        if not text:
            continue
        seen.append(text)
        slot: Dict[str, Any] = {
            "role": str(item.get("role") or "label"),
            "text": text,
        }
        label = _screen_text_phrase(item.get("label") or "", limit=10, seen_keys=seen)
        if label:
            slot["label"] = label
        screen_slots.append(slot)
        if len(screen_slots) >= 5:
            break
    timeline = []
    total_duration = sum(_positive_float(unit.get("duration_seconds"), 6.0) for unit in voice_units if isinstance(unit, dict)) or 6.0
    for item in (raw.get("timeline") if isinstance(raw.get("timeline"), list) else []):
        if not isinstance(item, dict):
            continue
        start_s = _positive_float(item.get("start_s") if item.get("start_s") is not None else item.get("at_s"), 0.0)
        end_s = _positive_float(item.get("end_s"), min(total_duration, start_s + 1.2))
        timeline.append(
            {
                "start_s": round(min(start_s, total_duration), 3),
                "end_s": round(max(min(end_s, total_duration), min(start_s, total_duration)), 3),
                "target": str(item.get("target") or "main_visual"),
                "action": _short_text(item.get("action") or item.get("motion") or "reveal", 40),
                "text": _screen_text_phrase(item.get("text") or "", limit=28),
            }
        )
        if len(timeline) >= 8:
            break
    metric = raw.get("supporting_metric") if isinstance(raw.get("supporting_metric"), dict) else {}
    return {
        "version": "mg_director_v1",
        "enabled": enabled,
        "render_strategy": render_strategy,
        "scope": scope if enabled else "single_shot",
        "bound_voiceover_unit_ids": bound_voice_ids if enabled else [],
        "story_goal": _short_text(raw.get("story_goal") or "", 120),
        "core_question": _short_text(raw.get("core_question") or "", 90),
        "one_learning_point": _short_text(raw.get("one_learning_point") or "", 90),
        "visual_system": visual_system,
        "main_visual_metaphor": _short_text(raw.get("main_visual_metaphor") or "", 120),
        "visual_recipe": raw.get("visual_recipe") if isinstance(raw.get("visual_recipe"), dict) else {},
        "composition": composition,
        "visual_fx": visual_fx,
        "logic_chain": logic_chain,
        "supporting_metric": {
            "label": _screen_text_phrase(metric.get("label") or "", limit=12),
            "text": _screen_text_phrase(metric.get("text") or "", limit=24),
            "date": _screen_text_phrase(metric.get("date") or "", limit=18),
        },
        "screen_slots": screen_slots,
        "timeline": timeline,
        "html_brief": _short_text(raw.get("html_brief") or "", 180),
    }


def _normalize_mg_visual_fx(value: Any, visual_system: str, semantic_text: str = "") -> Dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    fx_pack_id = str(raw.get("fx_pack_id") or raw.get("id") or "").strip().lower()
    fx_pack_id = fx_pack_id.replace("-", "_")
    aliases = {
        "gradient": "gradient_atmosphere",
        "gradients": "gradient_atmosphere",
        "ink": "ink_wash_reveal",
        "ink_wash": "ink_wash_reveal",
        "particle": "particle_field",
        "particles": "particle_field",
        "scan": "satellite_scan",
        "satellite": "satellite_scan",
        "film": "film_grain_archive",
        "grain": "film_grain_archive",
        "glow": "data_glow",
        "data": "data_glow",
    }
    fx_pack_id = aliases.get(fx_pack_id, fx_pack_id)
    if fx_pack_id not in VALID_MG_VISUAL_FX:
        text = semantic_text.lower()
        if visual_system == "route" or any(token in text for token in ["地图", "卫星", "扫描", "坐标", "路径"]):
            fx_pack_id = "satellite_scan"
        elif visual_system == "comparison" or any(token in text for token in ["对比", "前后", "分割", "转向"]):
            fx_pack_id = "gradient_atmosphere"
        elif any(token in text for token in ["历史", "档案", "资料", "殖民", "年代"]):
            fx_pack_id = "film_grain_archive"
        elif any(token in text for token in ["水墨", "传导", "扩散", "流动"]):
            fx_pack_id = "ink_wash_reveal"
        elif visual_system == "metric":
            fx_pack_id = "data_glow"
        elif visual_system == "causal":
            fx_pack_id = "particle_field"
        else:
            fx_pack_id = "none"
    opacity = _positive_float(raw.get("opacity"), 0.18)
    if fx_pack_id == "none":
        opacity = 0.0
    intensity = str(raw.get("intensity") or "low").strip().lower()
    if intensity not in {"low", "medium"}:
        intensity = "low"
    usage = _short_text(raw.get("usage") or _default_mg_visual_fx_usage(fx_pack_id), 120)
    return {
        "fx_pack_id": fx_pack_id,
        "intensity": intensity,
        "opacity": round(min(max(opacity, 0.0), 0.32), 3),
        "usage": usage,
    }


def _normalize_mg_composition(value: Any, visual_system: str, *, semantic_text: str = "") -> Dict[str, Any]:
    """Normalize the director's composition contract without turning it into a template.

    The director chooses the visual mechanism and spatial hierarchy. The HTML
    model still authors the actual SVG/CSS, but it no longer has to guess what
    should dominate the standalone HTML frame.
    """
    raw = value if isinstance(value, dict) else {}
    defaults = {
        "metric": ("single_focus", "metric_stage", (72, 96, 1776, 760), ["metric", "gauge", "icon"]),
        "causal": ("directional_path", "causal_spine", (72, 96, 1776, 760), ["path", "node", "icon"]),
        "route": ("directional_path", "map_path", (72, 84, 1776, 780), ["path", "map", "pin"]),
        "timeline": ("editorial_timeline", "timeline_stage", (72, 96, 1776, 760), ["axis", "event", "shape"]),
        "comparison": ("contrast_stage", "contrast_split", (72, 84, 1776, 780), ["divider", "contrast_field", "icon"]),
        "reveal": ("single_focus", "reveal_mask", (72, 84, 1776, 780), ["mask", "focus_ring", "icon"]),
    }
    default_layout, default_kind, default_hero, default_primitives = defaults.get(
        visual_system, defaults["comparison"]
    )
    animation_type = "self_contained_html"
    layout = str(raw.get("layout") or default_layout).strip().lower()
    if layout not in {"single_focus", "asymmetric_split", "editorial_timeline", "directional_path", "evidence_frame", "contrast_stage"}:
        layout = default_layout
    hero_raw = raw.get("hero_frame") if isinstance(raw.get("hero_frame"), dict) else {}

    def rect(source: Dict[str, Any], fallback: tuple[int, int, int, int]) -> Dict[str, int]:
        x = int(max(0, min(1800, _positive_float(source.get("x"), fallback[0]))))
        y = int(max(0, min(984, _positive_float(source.get("y"), fallback[1]))))
        w = int(max(120, min(1920 - x, _positive_float(source.get("w"), fallback[2]))))
        h = int(max(96, min(1080 - y, _positive_float(source.get("h"), fallback[3]))))
        return {"x": x, "y": y, "w": w, "h": h}

    primitives = [
        str(item).strip().lower()
        for item in (raw.get("visual_primitives") if isinstance(raw.get("visual_primitives"), list) else default_primitives)
        if str(item).strip()
    ]
    allowed_primitives = {"icon", "path", "node", "metric", "gauge", "map", "pin", "axis", "event", "media_frame", "divider", "contrast_field", "mask", "focus_ring", "shape"}
    primitives = [("shape" if item == "media_frame" else item) for item in primitives if item in allowed_primitives][:5] or default_primitives
    icon_semantics = [
        _screen_text_phrase(item, limit=14)
        for item in (raw.get("icon_semantics") if isinstance(raw.get("icon_semantics"), list) else [])
        if _screen_text_phrase(item, limit=14) and len(_screen_text_phrase(item, limit=14)) <= 10
    ][:3]
    if "icon" in primitives and not icon_semantics:
        icon_semantics = _icon_semantics_for_composition(semantic_text, visual_system)
    typography = raw.get("typography") if isinstance(raw.get("typography"), dict) else {}
    hero_frame = rect(hero_raw, default_hero)
    # A composition contract is allowed to be expressive, but its hero cannot
    # be a decorative corner object. Grow undersized director coordinates while
    # preserving their center and aspect ratio.
    min_coverage = 0.52
    hero_area = hero_frame["w"] * hero_frame["h"]
    target_area = int(DEFAULT_RENDER_WIDTH * DEFAULT_RENDER_HEIGHT * min_coverage)
    if hero_area < target_area:
        ratio = hero_frame["w"] / max(1, hero_frame["h"])
        target_w = min(1680, max(880, int((target_area * ratio) ** 0.5) + 1))
        target_h = min(820, max(420, int(target_w / max(0.2, ratio)) + 1))
        center_x = hero_frame["x"] + hero_frame["w"] / 2
        center_y = hero_frame["y"] + hero_frame["h"] / 2
        hero_frame = {
            "x": int(max(0, min(DEFAULT_RENDER_WIDTH - target_w, center_x - target_w / 2))),
            "y": int(max(0, min(DEFAULT_RENDER_HEIGHT - target_h, center_y - target_h / 2))),
            "w": target_w,
            "h": target_h,
        }
    if hero_frame["w"] * hero_frame["h"] < target_area:
        target_w = min(1776, max(hero_frame["w"], int(target_area / max(1, hero_frame["h"])) + 1))
        center_x = hero_frame["x"] + hero_frame["w"] / 2
        hero_frame["x"] = int(max(0, min(DEFAULT_RENDER_WIDTH - target_w, center_x - target_w / 2)))
        hero_frame["w"] = target_w
    hero_frame["coverage_percent"] = round(hero_frame["w"] * hero_frame["h"] / (DEFAULT_RENDER_WIDTH * DEFAULT_RENDER_HEIGHT) * 100, 1)
    return {
        "version": "mg_composition_v1",
        "animation_type": animation_type,
        "layout": layout,
        "hero_frame": {
            "kind": _short_text(hero_raw.get("kind") or default_kind, 32),
            **hero_frame,
        },
        "content_mode": "self_contained_html",
        "typography": {
            "headline_scale": "display" if str(typography.get("headline_scale") or "display") not in {"display", "large"} else str(typography.get("headline_scale") or "display"),
            "headline_min_px": int(max(48, min(128, _positive_float(typography.get("headline_min_px"), 64)))),
            "supporting_min_px": int(max(22, min(56, _positive_float(typography.get("supporting_min_px"), 28)))),
        },
        "visual_primitives": primitives,
        "icon_semantics": icon_semantics,
        "motion_choreography": _self_contained_html_direction(raw.get("motion_choreography")) or "先建立主视觉，再推进关系，最后锁定结论。",
    }


def _icon_semantics_for_composition(semantic_text: str, visual_system: str) -> List[str]:
    """Return drawable concepts, never narration fragments, for inline SVG icons."""
    text = str(semantic_text or "").lower()
    rules = [
        ("资本流", ("资本", "融资", "注资", "投资", "估值")),
        ("芯片算力", ("芯片", "算力", "gpu", "服务器", "计算")),
        ("云模型", ("模型", "ai", "大模型", "云", "openai", "anthropic")),
        ("公司主体", ("微软", "谷歌", "亚马逊", "meta", "苹果", "巨头", "公司")),
        ("数据网络", ("数据", "网络", "连接", "生态", "平台")),
        ("竞争对峙", ("竞争", "对峙", "围猎", "战", "博弈")),
        ("时间节点", ("时间", "年份", "季度", "阶段", "历程")),
        ("空间路径", ("地图", "路线", "流向", "路径", "区域")),
    ]
    selected = [label for label, signals in rules if any(signal in text for signal in signals)]
    if visual_system == "timeline":
        selected.append("时间节点")
    elif visual_system == "route":
        selected.append("空间路径")
    elif visual_system == "causal":
        selected.append("因果箭头")
    elif visual_system == "comparison":
        selected.append("竞争对峙")
    seen: List[str] = []
    for item in selected:
        if item not in seen:
            seen.append(item)
    return seen[:3] or ["核心概念", "关系路径"]


