def _broll_options(
    shot_id: str,
    prompt: str,
    duration_seconds: int,
    asset_search_plan: Dict[str, Any] | None = None,
) -> List[Dict[str, Any]]:
    asset_search_plan = asset_search_plan if isinstance(asset_search_plan, dict) else {}
    search_queries = _broll_search_queries(asset_search_plan.get("search_queries"), fallback=[prompt])
    named_entities = asset_search_plan.get("named_entities") if isinstance(asset_search_plan.get("named_entities"), list) else []
    themes = [
        {
            "title": "主推荐素材",
            "visual_style": "稳定横移、自然光、主体明确",
            "color": "from-cyan-500/50 via-slate-700 to-slate-950",
        },
        {
            "title": "近景补充素材",
            "visual_style": "特写镜头、浅景深、节奏更慢",
            "color": "from-emerald-500/45 via-teal-900 to-slate-950",
        },
        {
            "title": "氛围转场素材",
            "visual_style": "环境空镜、轻微运动、适合做过渡",
            "color": "from-amber-500/45 via-stone-800 to-slate-950",
        },
        {
            "title": "人物行为素材",
            "visual_style": "人物动作清楚、情绪自然、可承接口播",
            "color": "from-sky-500/45 via-blue-950 to-slate-950",
        },
        {
            "title": "空间建立素材",
            "visual_style": "广角环境、空间关系明确、适合段落开头",
            "color": "from-violet-500/40 via-indigo-950 to-slate-950",
        },
        {
            "title": "细节证据素材",
            "visual_style": "局部特写、信息明确、适合强调关键词",
            "color": "from-rose-500/40 via-zinc-900 to-slate-950",
        },
        {
            "title": "数据资料素材",
            "visual_style": "图表、屏幕、资料画面，便于叠加信息层",
            "color": "from-lime-500/35 via-slate-800 to-slate-950",
        },
        {
            "title": "结论收束素材",
            "visual_style": "节奏放缓、画面稳定、适合总结收尾",
            "color": "from-fuchsia-500/35 via-neutral-900 to-slate-950",
        },
    ]
    options: List[Dict[str, Any]] = []
    for index, theme in enumerate(themes, start=1):
        duration = max(4, duration_seconds + index - 2)
        query = str(search_queries[(index - 1) % len(search_queries)] if search_queries else _compact_broll_query(prompt))
        if named_entities and index % 2 == 0:
            query = _compact_broll_query(f"{query} {' '.join(str(item) for item in named_entities[:2])}", max_chars=96, max_terms=12)
        options.append(
            {
                "id": f"{shot_id}-broll-{index}",
                "title": theme["title"],
                "description": f"{query or prompt}；{theme['visual_style']}",
                "duration_seconds": duration,
                "visual_style": theme["visual_style"],
                "color": theme["color"],
                "asset_url": "",
                "asset_path": "",
                "search_query": query or prompt,
                "similar_materials": [
                    {
                        "id": f"{shot_id}-similar-{index}-{similar_index}",
                        "title": f"相似素材 {similar_index}",
                        "duration_seconds": max(5, duration + ((similar_index % 5) - 2)),
                        "color": theme["color"],
                    }
                    for similar_index in range(1, 9)
                ],
            }
        )
    return options


def _topic_keywords(topic: str) -> List[str]:
    clean_topic = topic.strip() or "主题"
    separators = ["为什么", "为何", "怎么", "如何", "越来越", "像", "？", "?", "，", ","]
    normalized = clean_topic
    for separator in separators:
        normalized = normalized.replace(separator, " ")
    keywords = [part.strip() for part in normalized.split() if len(part.strip()) >= 2]
    return keywords[:4] or [clean_topic]


def fallback_storyboard(topic: str, script: str, production_format: str, script_director: Dict[str, Any] | None = None) -> List[Dict[str, Any]]:
    clean_topic = topic.strip() or "这个主题"
    keywords = _topic_keywords(clean_topic)
    primary_keyword = keywords[0]
    secondary_keyword = keywords[1] if len(keywords) > 1 else clean_topic
    hook_strategy = (script_director or {}).get("hook_strategy") or "从一个日常反差开场，引出背后的机制。"
    structure = (script_director or {}).get("structure") or ["生活化设问", "解释背后机制", "行动建议"]
    shots = [
        {
            "id": "shot-01",
            "title": "开场设问",
            "narration": f"你有没有发现，{clean_topic}？",
            "duration_seconds": 6,
            "broll_prompt": f"{primary_keyword}真实场景、人物观察、自然光、城市生活细节",
        },
        {
            "id": "shot-02",
            "title": "现象展开",
            "narration": f"这不是单个店铺的变化，而是{secondary_keyword}需求正在进入日常消费空间。",
            "duration_seconds": 7,
            "broll_prompt": f"{primary_keyword}空间、人群停留、电脑办公、消费场景切换",
        },
        {
            "id": "shot-03",
            "title": "机制解释",
            "narration": f"背后的关键机制，是用户把{primary_keyword}当成了低门槛、可停留、能工作的第三空间。",
            "duration_seconds": 8,
            "broll_prompt": f"{primary_keyword}座位布局、插座、笔记本电脑、多人安静办公、空间动线",
        },
        {
            "id": "shot-04",
            "title": "行动建议",
            "narration": f"所以看{clean_topic}，不要只看咖啡本身，要看它承接了哪一类新的生活需求。",
            "duration_seconds": 7,
            "broll_prompt": f"{primary_keyword}外立面、顾客离开、城市街区、消费与办公融合",
        },
    ]
    hydrated_shots = [
        {
            **shot,
            "scene_role": BROLL_BACKDROP if production_format == "broll_html" and index % 3 != 0 else FULL_BROLL,
            "visual_role": "hybrid_broll_html" if production_format == "broll_html" and index % 3 != 0 else "broll_primary",
            "information_layer": _information_layer_for_shot(
                shot,
                shot["id"],
                shot["narration"],
                shot["broll_prompt"],
                BROLL_BACKDROP if production_format == "broll_html" and index % 3 != 0 else FULL_BROLL,
            ),
            "broll_options": _broll_options(shot["id"], shot["broll_prompt"], shot["duration_seconds"]),
        }
        for index, shot in enumerate(shots, start=1)
    ]
    html_layers = []
    if production_format == "broll_html":
        html_layers = [
            {
                "id": "html-layer-01",
                "title": "现象到机制信息卡",
                "shot_ids": ["shot-02", "shot-03"],
                "description": f"用信息卡把“{structure[0]} / {structure[1]} / {structure[-1]}”串起来，解释{clean_topic}的机制。",
                "style": {
                    "palette": ["#14B8A6", "#0F172A", "#F8FAFC"],
                    "typography": "醒目标题 + 简短说明",
                    "motion": "卡片从下方滑入，关键词轻微放大",
                },
                "safe_area": "lower_third",
            }
        ]
    fallback_director = {"html_motion_director": _normalize_html_motion_director({}, clean_topic)} if production_format == "broll_html" else {}
    return _hydrate_group_timing([
        {
            "id": "group-01",
            "title": "现象切入",
            "intent": hook_strategy,
            "shots": hydrated_shots[:2],
            "html_layers": [],
        },
        {
            "id": "group-02",
            "title": "机制解释与行动建议",
            "intent": f"围绕“{clean_topic}”解释变化原因，并给出观察框架。",
            "shots": hydrated_shots[2:],
            "html_layers": html_layers,
        },
    ], fallback_director)
